const Pill = ({ children, tone = "neutral", className = "" }) => {
  const tones = {
    neutral: { background: "#f5f5f4", color: "#292524", border: "#d6d3d1" },
    good:    { background: "rgba(157,197,68,0.2)", color: "#3d5017", border: "#9dc544" },
    bad:     { background: "rgba(237,110,108,0.2)", color: "#8a2422", border: "#ed6e6c" },
    warn:    { background: "rgba(196,192,179,0.4)", color: "#292524", border: "#c4c0b3" },
    ink:     { background: "#275662", color: "#ffffff", border: "#275662" },
    primary: { background: "rgba(0,163,166,0.15)", color: "#275662", border: "#00a3a6" },
    violet:  { background: "rgba(66,48,137,0.10)", color: "#423089", border: "#423089" },
  };
  const t = tones[tone] || tones.neutral;
  return (
    <span
      className={`inline-flex items-center gap-1 px-2 py-0.5 text-[11px] font-semibold border rounded-sm ${className}`}
      style={{
        fontFamily: '"Raleway", sans-serif',
        background: t.background,
        color: t.color,
        borderColor: t.border,
      }}
    >
      {children}
    </span>
  );
};

/** Renders a row of metadata-derived pills for a single sample.
    `compact` skips the lower-priority flags (subject, timepoint, other)
    so it doesn't dominate dense tables. */
const SampleFlags = ({ flags, compact = false }) => {
  if (!flags) return null;
  const items = [];

  if (flags.isControl) {
    items.push(
      <Pill key="ctrl" tone="bad">
        <ShieldAlert className="w-3 h-3" />
        control
      </Pill>,
    );
  }
  if (flags.isLowBiomass) {
    items.push(
      <Pill key="lb" tone="warn">
        <Droplets className="w-3 h-3" />
        low biomass
      </Pill>,
    );
  }
  // Skip the biome pill when it carries no info beyond "this is a control"
  // (the shield pill above already conveys that).
  if (flags.biome && !flags.isControl) {
    items.push(
      <Pill key="bio" tone="primary">
        <Beaker className="w-3 h-3" />
        {flags.biome}
      </Pill>,
    );
  }
  if (!compact) {
    if (flags.subject) {
      items.push(
        <Pill key="subj" tone="neutral">
          <User className="w-3 h-3" />
          {flags.subject}
        </Pill>,
      );
    }
    if (flags.timepoint) {
      items.push(
        <Pill key="tp" tone="neutral">
          <Calendar className="w-3 h-3" />
          {flags.timepoint}
        </Pill>,
      );
    }
    if (flags.groupId) {
      items.push(
        <Pill key="grp" tone="violet">
          <Users className="w-3 h-3" />
          {flags.groupId}
        </Pill>,
      );
    }
    Object.entries(flags.other || {}).forEach(([k, v]) => {
      items.push(
        <Pill key={`o-${k}`} tone="neutral">
          <span style={{ opacity: 0.6, fontWeight: 500 }}>{k}:</span> {v}
        </Pill>,
      );
    });
  }

  if (items.length === 0) return null;
  return <div className="flex flex-wrap items-center gap-1">{items}</div>;
};

/** Small "?" affordance with a contextual tooltip. Hover to peek, click
    to lock open until the next click anywhere on the page. The tooltip
    panel itself stops propagation so users can read or copy text inside
    without it auto-closing. */
const InfoTooltip = ({ children, side = "top", className = "" }) => {
  const [hover, setHover] = useState(false);
  const [locked, setLocked] = useState(false);
  const visible = hover || locked;

  // Click-anywhere-to-close behaviour for the locked state.
  useEffect(() => {
    if (!locked) return undefined;
    const onDown = () => setLocked(false);
    // Defer so the click that opened it doesn't immediately close it
    const t = setTimeout(() => {
      window.addEventListener("mousedown", onDown);
    }, 0);
    return () => {
      clearTimeout(t);
      window.removeEventListener("mousedown", onDown);
    };
  }, [locked]);

  const tooltipStyle = {
    position: "absolute",
    minWidth: 240,
    maxWidth: 320,
    padding: "10px 12px",
    background: "#275662",
    color: "#fff",
    borderRadius: 3,
    fontSize: 12,
    lineHeight: 1.5,
    fontFamily: '"Raleway", sans-serif',
    fontWeight: 500,
    boxShadow: "0 4px 12px rgba(39,86,98,0.25)",
    zIndex: 50,
    whiteSpace: "normal",
    pointerEvents: "auto",
  };

  // Position panel relative to the trigger button.
  if (side === "top") {
    tooltipStyle.bottom = "calc(100% + 6px)";
    tooltipStyle.left = "50%";
    tooltipStyle.transform = "translateX(-50%)";
  } else if (side === "right") {
    tooltipStyle.left = "calc(100% + 6px)";
    tooltipStyle.top = "50%";
    tooltipStyle.transform = "translateY(-50%)";
  } else if (side === "bottom") {
    tooltipStyle.top = "calc(100% + 6px)";
    tooltipStyle.left = "50%";
    tooltipStyle.transform = "translateX(-50%)";
  } else if (side === "left") {
    tooltipStyle.right = "calc(100% + 6px)";
    tooltipStyle.top = "50%";
    tooltipStyle.transform = "translateY(-50%)";
  }

  return (
    <span
      className={`relative inline-flex ${className}`}
      onMouseEnter={() => setHover(true)}
      onMouseLeave={() => setHover(false)}
    >
      <button
        type="button"
        onClick={(e) => {
          e.stopPropagation();
          setLocked((v) => !v);
        }}
        aria-label="More info"
        className="inline-flex items-center justify-center rounded-full"
        style={{
          width: 16,
          height: 16,
          background: visible ? "#00a3a6" : "#c4c0b3",
          color: "#fff",
          fontSize: 11,
          fontWeight: 700,
          fontFamily: '"Raleway", sans-serif',
          cursor: "help",
          border: "none",
          lineHeight: 1,
          transition: "background 0.15s",
        }}
      >
        ?
      </button>
      {visible && (
        <span
          role="tooltip"
          style={tooltipStyle}
          onMouseDown={(e) => e.stopPropagation()}
        >
          {children}
        </span>
      )}
    </span>
  );
};

