/* ---------- SCATTERPLOT ---------- */
const Scatterplot = ({ scatter, width = 560, height = 500 }) => {
  const [hover, setHover] = useState(null);
  if (!scatter) return null;
  if (scatter.error) {
    return (
      <div
        style={{
          width,
          height,
          background: "#fdeceb",
          border: "1px solid #ed6e6c",
          borderRadius: 2,
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          padding: 16,
          color: "#8a2422",
          textAlign: "center",
          gap: 8,
        }}
      >
        <AlertCircle className="w-5 h-5" />
        <div style={{ fontSize: 13, fontWeight: 600 }}>{scatter.error}</div>
        <div style={{ fontSize: 11, color: "#8a2422", opacity: 0.8, maxWidth: 380 }}>
          Check that sample IDs in contamination_events.tsv exactly match the
          column names in species_abundance.tsv (case-sensitive).
        </div>
      </div>
    );
  }
  const pad = { l: 56, r: 20, t: 20, b: 50 };
  const w = width - pad.l - pad.r;
  const h = height - pad.t - pad.b;

  const floor = 1e-8;
  const pts = scatter.points.map((p) => ({
    ...p,
    lx: Math.log10(Math.max(p.x, floor)),
    ly: Math.log10(Math.max(p.y, floor)),
  }));
  const allX = pts.map((p) => p.lx);
  const allY = pts.map((p) => p.ly);
  const minL = Math.min(Math.log10(floor), ...allX, ...allY);
  const maxL = Math.max(...allX, ...allY, -2);
  const lo = Math.floor(minL);
  const hi = Math.ceil(maxL);

  const sx = (v) => pad.l + ((v - lo) / (hi - lo)) * w;
  const sy = (v) => pad.t + h - ((v - lo) / (hi - lo)) * h;

  const ticks = [];
  for (let i = lo; i <= hi; i++) ticks.push(i);

  // y=x identity line: indicates "same abundance in source and target".
  // Dashed so it's distinguishable from the (also-diagonal) contamination line.
  const diagLine = (
    <line
      x1={sx(lo)}
      y1={sy(lo)}
      x2={sx(hi)}
      y2={sy(hi)}
      stroke="#000000"
      strokeWidth="1.25"
      strokeDasharray="2 4"
      strokeOpacity="0.75"
    />
  );

  const lineEls =
    scatter.logC != null ? (
      <line
        x1={sx(lo)}
        y1={sy(lo - scatter.logC)}
        x2={sx(hi)}
        y2={sy(hi - scatter.logC)}
        stroke="#ed6e6c"
        strokeWidth="1.75"
        strokeDasharray="5 3"
      />
    ) : null;

  return (
    <div
      className="relative"
      style={{ width: "100%", maxWidth: width }}
    >
      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="border border-stone-300 rounded-sm"
        style={{
          background: "#fff",
          width: "100%",
          height: "auto",
          display: "block",
        }}
      >
        {ticks.map((t) => (
          <g key={`gx-${t}`}>
            <line x1={sx(t)} y1={pad.t} x2={sx(t)} y2={pad.t + h} stroke="#eee" strokeWidth="0.5" />
            <text
              x={sx(t)}
              y={pad.t + h + 16}
              textAnchor="middle"
              fontSize="10"
              fontFamily="system-ui, sans-serif"
              fill="#797870"
            >
              10{sup(t)}
            </text>
          </g>
        ))}
        {ticks.map((t) => (
          <g key={`gy-${t}`}>
            <line x1={pad.l} y1={sy(t)} x2={pad.l + w} y2={sy(t)} stroke="#eee" strokeWidth="0.5" />
            <text
              x={pad.l - 8}
              y={sy(t) + 3}
              textAnchor="end"
              fontSize="10"
              fontFamily="system-ui, sans-serif"
              fill="#797870"
            >
              10{sup(t)}
            </text>
          </g>
        ))}
        <line x1={pad.l} y1={pad.t + h} x2={pad.l + w} y2={pad.t + h} stroke="#275662" strokeWidth="1" />
        <line x1={pad.l} y1={pad.t} x2={pad.l} y2={pad.t + h} stroke="#275662" strokeWidth="1" />
        <text
          x={pad.l + w / 2}
          y={height - 10}
          textAnchor="middle"
          fontSize="11"
          fontFamily="Raleway, sans-serif"
          fontWeight="600"
          fill="#275662"
        >
          Target (contaminated) — {scatter.target}
        </text>
        <text
          x={-(pad.t + h / 2)}
          y={14}
          transform="rotate(-90)"
          textAnchor="middle"
          fontSize="11"
          fontFamily="Raleway, sans-serif"
          fontWeight="600"
          fill="#275662"
        >
          Source — {scatter.source}
        </text>
        {lineEls}
        {pts.map((p, i) => (
          <circle
            key={i}
            cx={sx(p.lx)}
            cy={sy(p.ly)}
            r={p.onLine ? 4 : 2.8}
            fill={p.onLine ? "#ed6e6c" : "#275662"}
            fillOpacity={p.onLine ? 0.9 : 0.35}
            stroke={p.onLine ? "#b84442" : "none"}
            strokeWidth="0.7"
            onMouseEnter={() =>
              setHover({
                species: p.species,
                x: p.x,
                y: p.y,
                sx: sx(p.lx),
                sy: sy(p.ly),
                onLine: p.onLine,
              })
            }
            onMouseLeave={() => setHover(null)}
            style={{ cursor: "pointer" }}
          />
        ))}
        {diagLine}
      </svg>
      {hover && (
        <div
          className="absolute pointer-events-none text-[11px] px-2 py-1 shadow-lg rounded-sm"
          style={{
            left: `calc(${(hover.sx / width) * 100}% + 12px)`,
            top: `calc(${(hover.sy / height) * 100}% - 8px)`,
            maxWidth: 260,
            background: "#275662",
            color: "white",
            fontFamily: "system-ui, sans-serif",
          }}
        >
          <div className="truncate font-semibold">{hover.species}</div>
          <div style={{ opacity: 0.75 }}>target: {hover.x.toExponential(2)}</div>
          <div style={{ opacity: 0.75 }}>source: {hover.y.toExponential(2)}</div>
          {hover.onLine && (
            <div style={{ color: "#ed6e6c" }}>● on contamination line</div>
          )}
        </div>
      )}
    </div>
  );
};

/* ---------- NETWORK GRAPH ---------- */
/** Build connected components from a list of (source, target) edges,
    treating the graph as undirected for grouping purposes. */
function buildComponents(events) {
  const parent = {};
  const find = (x) => {
    if (parent[x] !== x) parent[x] = find(parent[x]);
    return parent[x];
  };
  const union = (a, b) => {
    const ra = find(a);
    const rb = find(b);
    if (ra !== rb) parent[ra] = rb;
  };

  events.forEach((e) => {
    if (parent[e.source] === undefined) parent[e.source] = e.source;
    if (parent[e.target] === undefined) parent[e.target] = e.target;
    union(e.source, e.target);
  });

  const comps = {};
  Object.keys(parent).forEach((node) => {
    const root = find(node);
    if (!comps[root]) comps[root] = { nodes: new Set(), edges: [] };
    comps[root].nodes.add(node);
  });
  events.forEach((e) => {
    const root = find(e.source);
    comps[root].edges.push(e);
  });

  // Convert to array, sort by size descending so big components go first
  return Object.values(comps)
    .map((c) => ({ nodes: Array.from(c.nodes), edges: c.edges }))
    .sort((a, b) => b.nodes.length - a.nodes.length);
}

/** Lay out one connected component inside its allocated cell. Returns
    { nodes: [{id, x, y}], edges: events_unchanged }. */
function layoutComponent(comp, cellWidth, cellHeight) {
  const { nodes, edges } = comp;
  const cx = cellWidth / 2;
  const cy = cellHeight / 2;
  const positions = {};

  if (nodes.length === 1) {
    positions[nodes[0]] = { x: cx, y: cy };
  } else if (nodes.length === 2 && edges.length === 1) {
    // Simple pair: horizontal arrow
    const e = edges[0];
    positions[e.source] = { x: cellWidth * 0.28, y: cy };
    positions[e.target] = { x: cellWidth * 0.72, y: cy };
  } else {
    // Larger component: use a force-directed simulation that runs
    // synchronously to convergence. d3 handles repulsion, edge attraction,
    // and collision so dense components no longer overlap.
    const simNodes = nodes.map((id) => ({ id }));
    const simLinks = edges.map((e) => ({
      source: e.source,
      target: e.target,
    }));

    const simulation = d3
      .forceSimulation(simNodes)
      .force(
        "link",
        d3
          .forceLink(simLinks)
          .id((d) => d.id)
          .distance(85)
          .strength(0.6),
      )
      .force("charge", d3.forceManyBody().strength(-260))
      .force("center", d3.forceCenter(cx, cy))
      .force("collide", d3.forceCollide(34))
      // Mild horizontal spread proportional to net flow direction
      // (sources tend left, targets tend right) — avoids the layout
      // collapsing to a vertical column.
      .force("x", d3.forceX(cx).strength(0.05))
      .force("y", d3.forceY(cy).strength(0.08))
      .stop();

    // Run the simulation to completion synchronously (no animation —
    // we just want the converged layout).
    const ITERATIONS = 300;
    for (let i = 0; i < ITERATIONS; i++) simulation.tick();

    // Clamp inside the cell with a small padding so nodes never sit on the edge.
    const pad = 28;
    simNodes.forEach((n) => {
      positions[n.id] = {
        x: Math.max(pad, Math.min(cellWidth - pad, n.x)),
        y: Math.max(pad, Math.min(cellHeight - pad, n.y)),
      };
    });
  }

  return {
    nodes: nodes.map((id) => ({ id, ...positions[id] })),
    edges,
  };
}

const NetworkGraph = ({ events, onPick }) => {
  const [hover, setHover] = useState(null);
  const [zoom, setZoom] = useState({ k: 1, x: 0, y: 0 });
  const svgRef = useRef(null);
  const zoomBehaviorRef = useRef(null);

  const components = useMemo(() => buildComponents(events), [events]);

  // Pick cell dimensions based on the size of the LARGEST component.
  // Small graphs (pairs only) keep compact cells; complex graphs get
  // proportionally more space so the force layout has room to spread.
  const { cellWidth, cellHeight, grid } = useMemo(() => {
    const n = components.length;
    if (n === 0) return { cellWidth: 280, cellHeight: 180, grid: { cols: 1, rows: 1 } };

    const maxNodes = Math.max(...components.map((c) => c.nodes.length));
    let cw, ch;
    if (maxNodes <= 2) {
      cw = 260;
      ch = 130;
    } else if (maxNodes <= 4) {
      cw = 320;
      ch = 220;
    } else if (maxNodes <= 8) {
      cw = 380;
      ch = 280;
    } else {
      cw = 460;
      ch = 360;
    }

    let cols;
    if (n <= 2) cols = n;
    else if (n <= 4) cols = 2;
    else if (n <= 9) cols = 3;
    else cols = 4;

    return {
      cellWidth: cw,
      cellHeight: ch,
      grid: { cols, rows: Math.ceil(n / cols) },
    };
  }, [components]);

  const totalWidth = grid.cols * cellWidth;
  const totalHeight = grid.rows * cellHeight + 40; // +40 for legend

  // Lay out each component, then translate to its grid cell
  const laidOut = useMemo(() => {
    return components.map((comp, i) => {
      const col = i % grid.cols;
      const row = Math.floor(i / grid.cols);
      const layout = layoutComponent(comp, cellWidth, cellHeight);
      const ox = col * cellWidth;
      const oy = 40 + row * cellHeight;
      const positioned = {};
      layout.nodes.forEach((n) => {
        positioned[n.id] = { id: n.id, x: ox + n.x, y: oy + n.y };
      });
      return { nodes: positioned, edges: layout.edges };
    });
  }, [components, grid]);

  const allNodes = useMemo(() => {
    const out = [];
    laidOut.forEach((c) => {
      Object.values(c.nodes).forEach((n) => out.push(n));
    });
    return out;
  }, [laidOut]);

  const nodeIdx = useMemo(() => {
    const m = new Map();
    allNodes.forEach((n) => m.set(n.id, n));
    return m;
  }, [allNodes]);

  const inDeg = useMemo(() => {
    const d = {};
    events.forEach((e) => (d[e.target] = (d[e.target] || 0) + 1));
    return d;
  }, [events]);
  const outDeg = useMemo(() => {
    const d = {};
    events.forEach((e) => (d[e.source] = (d[e.source] || 0) + 1));
    return d;
  }, [events]);

  // Wire d3.zoom: drag to pan, wheel/pinch to zoom.
  // Bounds: 0.4× to 4× — enough to see overview and zoom into dense clusters.
  useEffect(() => {
    if (!svgRef.current) return;
    const svgSel = d3.select(svgRef.current);
    const zoomBehavior = d3
      .zoom()
      .scaleExtent([0.4, 4])
      .filter((event) => {
        // Don't start a pan when the user clicked on a node or an edge —
        // those have their own click handlers (open in Guided validation).
        // Allow zoom (wheel) and pan from background only.
        if (event.type === "wheel") return true;
        const target = event.target;
        if (!target) return true;
        // The transform group contains nodes and edges; clicks on those
        // should not trigger a pan. Background <rect> below sits behind
        // the transform group and IS pannable.
        return target.tagName === "rect" && target.dataset?.bg === "1";
      })
      .on("zoom", (event) => {
        const { k, x, y } = event.transform;
        setZoom({ k, x, y });
      });
    zoomBehaviorRef.current = zoomBehavior;
    svgSel.call(zoomBehavior);
    return () => {
      svgSel.on(".zoom", null);
    };
  }, []);

  const resetZoom = () => {
    if (!svgRef.current || !zoomBehaviorRef.current) return;
    d3.select(svgRef.current)
      .transition()
      .duration(250)
      .call(zoomBehaviorRef.current.transform, d3.zoomIdentity);
  };

  return (
    <div
      className="border border-stone-300 rounded-sm bg-white overflow-hidden"
      style={{ position: "relative" }}
    >
      {/* HTML overlay: legend (top-left, never zooms) */}
      <div
        className="absolute z-10 flex items-center gap-4 px-3 py-1.5 rounded-sm pointer-events-none"
        style={{
          top: 8,
          left: 8,
          background: "rgba(255,255,255,0.92)",
          border: "1px solid #e6e8e8",
        }}
      >
        <span
          className="text-[10px] tracking-[0.1em] uppercase"
          style={{ color: "#275662", fontWeight: 700, fontFamily: '"Raleway", sans-serif' }}
        >
          Legend
        </span>
        <span className="flex items-center gap-1.5 text-[10px]" style={{ color: "#275662" }}>
          <span className="inline-block w-2.5 h-2.5 rounded-full" style={{ background: "#fff", border: "1.2px solid #275662" }} />
          source only
        </span>
        <span className="flex items-center gap-1.5 text-[10px]" style={{ color: "#275662" }}>
          <span className="inline-block w-2.5 h-2.5 rounded-full" style={{ background: "#275662" }} />
          target only
        </span>
        <span className="flex items-center gap-1.5 text-[10px]" style={{ color: "#275662" }}>
          <span className="inline-block w-2.5 h-2.5 rounded-full" style={{ background: "#ed6e6c" }} />
          cascade (both)
        </span>
      </div>

      {/* HTML overlay: zoom controls (top-right) */}
      <div
        className="absolute z-10 flex items-center gap-1"
        style={{ top: 8, right: 8 }}
      >
        <span
          className="text-[10px] tabular px-2"
          style={{
            color: "#797870",
            fontFamily: "system-ui, monospace",
            background: "rgba(255,255,255,0.92)",
            borderRadius: 2,
            padding: "3px 6px",
            border: "1px solid #e6e8e8",
          }}
        >
          {Math.round(zoom.k * 100)}%
        </span>
        <button
          onClick={resetZoom}
          className="text-[10px] px-2 py-0.5 rounded-sm"
          style={{
            background: "#fff",
            color: "#275662",
            border: "1px solid #c4c0b3",
            fontWeight: 600,
            fontFamily: '"Raleway", sans-serif',
          }}
        >
          Reset view
        </button>
      </div>

      <svg
        ref={svgRef}
        width="100%"
        height={totalHeight}
        viewBox={`0 0 ${totalWidth} ${totalHeight}`}
        style={{ display: "block", cursor: zoom.k > 1 ? "grab" : "default" }}
      >
        <defs>
          <marker
            id="arrow-inrae"
            viewBox="0 0 10 10"
            refX="9"
            refY="5"
            markerWidth="6"
            markerHeight="6"
            orient="auto-start-reverse"
          >
            <path d="M 0 0 L 10 5 L 0 10 z" fill="#00a3a6" />
          </marker>
        </defs>

        {/* Background rect — receives pan drags. Click-through everywhere
            except where this rect lives (i.e. the empty canvas). */}
        <rect
          data-bg="1"
          x="0"
          y="0"
          width={totalWidth}
          height={totalHeight}
          fill="transparent"
        />

        {/* Everything below transforms with zoom/pan */}
        <g transform={`translate(${zoom.x},${zoom.y}) scale(${zoom.k})`}>

        {/* Edges (drawn first so nodes overlay endpoints) */}
        {laidOut.map((c) => {
          // For dense components, hide non-hovered rate badges to reduce clutter.
          // ≤ 2 edges = always show; otherwise only on hover.
          const isCompact = c.edges.length <= 2;
          return c.edges.map((e) => {
            const a = c.nodes[e.source];
            const b = c.nodes[e.target];
            if (!a || !b) return null;
            const rejected = e.verdict === "false_positive";
            const accepted = e.verdict === "true_positive";
            const isHovered = hover?.kind === "edge" && hover.e.id === e.id;

            // Trim endpoints back from the node circles (radius 14)
            const dx = b.x - a.x;
            const dy = b.y - a.y;
            const dist = Math.sqrt(dx * dx + dy * dy) || 1;
            const ux = dx / dist;
            const uy = dy / dist;
            const r = 16;
            const x1 = a.x + ux * r;
            const y1 = a.y + uy * r;
            const x2 = b.x - ux * r;
            const y2 = b.y - uy * r;
            const mx = (x1 + x2) / 2;
            const my = (y1 + y2) / 2;

            // Show badge only when the layout has space: simple components
            // always show; complex components show only on hover.
            const showBadge =
              dist > 60 && (isCompact || isHovered);

            return (
              <g key={e.id}>
                {/* invisible wider hit line */}
                <line
                  x1={x1}
                  y1={y1}
                  x2={x2}
                  y2={y2}
                  stroke="transparent"
                  strokeWidth="14"
                  onMouseEnter={() => setHover({ kind: "edge", e })}
                  onMouseLeave={() => setHover(null)}
                  onClick={() => onPick && onPick(e.id)}
                  style={{ cursor: "pointer" }}
                />
                {/* visible edge — thickness AND color intensity scale with
                    contamination rate (log-scaled, since rates span several
                    orders of magnitude). Higher rate = thicker, darker line. */}
                {(() => {
                  // log10(rate * 100) maps 0.01% → -2, 1% → 0, 100% → 2.
                  // Normalize to [0, 1] over [-3, 2] (covers 0.001% to 100%).
                  const r = Math.max(e.rate || 0, 1e-5);
                  const logRate = Math.log10(r * 100); // -3 to 2
                  const t = Math.max(0, Math.min(1, (logRate + 3) / 5)); // 0..1

                  // Stroke: 1.2 (low rate) → 4.5 (high rate) base width
                  const baseWidth = 1.2 + t * 3.3;
                  const strokeColor = rejected
                    ? "#c4c0b3"
                    : accepted
                      ? "#00a3a6"
                      : // Lerp from light teal-grey (#7a9aa1) to deep teal (#1d3a44)
                        // so high-rate events stand out as visually heavier.
                        d3.interpolateRgb("#9aaab0", "#1d3a44")(t);

                  return (
                    <line
                      x1={x1}
                      y1={y1}
                      x2={x2}
                      y2={y2}
                      stroke={strokeColor}
                      strokeOpacity={isHovered ? 1 : rejected ? 0.4 : 0.85}
                      strokeWidth={baseWidth + (isHovered ? 1.5 : 0)}
                      strokeDasharray={rejected ? "3 3" : undefined}
                      markerEnd="url(#arrow-inrae)"
                      style={{ pointerEvents: "none" }}
                    />
                  );
                })()}
                {/* rate badge on the edge */}
                {showBadge && (
                  <g pointerEvents="none">
                    <rect
                      x={mx - 22}
                      y={my - 9}
                      width="44"
                      height="14"
                      rx="2"
                      fill="#fff"
                      stroke={
                        rejected ? "#c4c0b3" : accepted ? "#00a3a6" : "#275662"
                      }
                      strokeWidth="0.8"
                      opacity={isHovered ? 1 : 0.95}
                    />
                    <text
                      x={mx}
                      y={my + 1}
                      textAnchor="middle"
                      fontSize="9"
                      fontFamily="system-ui, sans-serif"
                      fontWeight="600"
                      fill="#275662"
                    >
                      {(e.rate * 100).toFixed(1)}%
                    </text>
                  </g>
                )}
              </g>
            );
          });
        })}

        {/* Nodes — circle + external label below */}
        {allNodes.map((n) => {
          const isSource = (outDeg[n.id] || 0) > 0 && (inDeg[n.id] || 0) === 0;
          const isTarget = (inDeg[n.id] || 0) > 0 && (outDeg[n.id] || 0) === 0;
          const isBoth = (inDeg[n.id] || 0) > 0 && (outDeg[n.id] || 0) > 0;
          const fill = isSource
            ? "#fff"
            : isTarget
              ? "#275662"
              : isBoth
                ? "#ed6e6c"
                : "#fff";
          const isNodeHover = hover?.kind === "node" && hover.n.id === n.id;
          return (
            <g
              key={n.id}
              onMouseEnter={() => setHover({ kind: "node", n })}
              onMouseLeave={() => setHover(null)}
              style={{ cursor: "pointer" }}
            >
              <circle
                cx={n.x}
                cy={n.y}
                r={isNodeHover ? 13 : 11}
                fill={fill}
                stroke="#275662"
                strokeWidth={isNodeHover ? 2.5 : 1.5}
              />
              {/* External label below node — white halo for readability over edges */}
              <text
                x={n.x}
                y={n.y + 28}
                textAnchor="middle"
                fontSize="12"
                fontFamily="system-ui, sans-serif"
                fontWeight="700"
                fill="#275662"
                stroke="#ffffff"
                strokeWidth="2"
                strokeLinejoin="round"
                paintOrder="stroke fill"
                style={{ pointerEvents: "none" }}
              >
                {n.id}
              </text>
            </g>
          );
        })}
        </g>
      </svg>

      {hover?.kind === "node" && (
        <div className="px-3 py-2 text-[12px] border-t border-stone-300 bg-[#f6f7f7]">
          <span className="text-stone-500">sample:</span>{" "}
          <span className="font-semibold" style={{ color: "#275662" }}>
            {hover.n.id}
          </span>
          <span className="text-stone-500 ml-3">contaminates:</span>{" "}
          {outDeg[hover.n.id] || 0}
          <span className="text-stone-500 ml-3">contaminated by:</span>{" "}
          {inDeg[hover.n.id] || 0}
        </div>
      )}
      {hover?.kind === "edge" && (
        <div className="px-3 py-2 text-[12px] border-t border-stone-300 bg-[#f6f7f7] flex items-center gap-2 flex-wrap">
          <span className="font-semibold" style={{ color: "#275662" }}>
            {hover.e.source}
          </span>
          <ArrowRight className="inline w-3 h-3" style={{ color: "#00a3a6" }} />
          <span className="font-semibold" style={{ color: "#275662" }}>
            {hover.e.target}
          </span>
          <span className="text-stone-500 ml-2">rate:</span>{" "}
          {(hover.e.rate * 100).toFixed(2)}%
          <span className="text-stone-500 ml-2">probability:</span>{" "}
          {hover.e.score.toFixed(3)}
          <span
            className="ml-auto text-[11px]"
            style={{ color: "#00a3a6", fontWeight: 600 }}
          >
            click to open →
          </span>
        </div>
      )}
    </div>
  );
};

/* ---------- PLATE GRID ---------- */
const PlateGrid = ({
  format,
  plateId,
  plateMap,
  highlightSamples = {},
  onClickWell,
  editable = false,
  labelMode = "sample",
  size = 26,
  focus = null,
  arrows = null, // array of {fromRow, fromCol, toRow, toCol, color, opacity, width, key}
}) => {
  const rows = format?.rows || 8;
  const cols = format?.cols || 12;

  const grid = useMemo(() => {
    const g = {};
    if (!plateMap) return g;
    Object.entries(plateMap.bySample).forEach(([sid, p]) => {
      if (p.plate !== plateId) return;
      g[`${p.row}-${p.col}`] = sid;
    });
    return g;
  }, [plateMap, plateId]);

  const rowLabel = (r) => String.fromCharCode(65 + r);

  return (
    <div className="inline-block" style={{ position: "relative" }}>
      <div
        className="grid"
        style={{
          gridTemplateColumns: `${size}px repeat(${cols}, ${size}px)`,
          gridTemplateRows: `${size}px repeat(${rows}, ${size}px)`,
          gap: 2,
        }}
      >
        <div />
        {Array.from({ length: cols }, (_, c) => (
          <div
            key={`ch-${c}`}
            className="flex items-center justify-center text-[10px]"
            style={{
              color: "#797870",
              fontWeight: 700,
              fontFamily: '"Raleway", sans-serif',
            }}
          >
            {c + 1}
          </div>
        ))}
        {Array.from({ length: rows }, (_, r) => (
          <React.Fragment key={`row-${r}`}>
            <div
              className="flex items-center justify-center text-[10px]"
              style={{
                color: "#797870",
                fontWeight: 700,
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              {rowLabel(r)}
            </div>
            {Array.from({ length: cols }, (_, c) => {
              const sid = grid[`${r}-${c}`];
              const highlight = sid ? highlightSamples[sid] : null;
              const filled = !!sid;
              const isFocused = focus && focus.row === r && focus.col === c;
              return (
                <button
                  key={`w-${r}-${c}`}
                  onClick={() => onClickWell && onClickWell(r, c, sid)}
                  className="rounded-sm flex items-center justify-center"
                  style={{
                    width: size,
                    height: size,
                    background: highlight || (filled ? "#f6f7f7" : "#fff"),
                    border: highlight
                      ? `1.5px solid ${highlight}`
                      : filled
                        ? "1px solid #c4c0b3"
                        : "1px dashed #e6e8e8",
                    color: highlight ? "#fff" : "#275662",
                    cursor: editable || onClickWell ? "pointer" : "default",
                    fontSize: size >= 44 ? 9 : size >= 32 ? 8 : 7,
                    fontFamily: "system-ui, sans-serif",
                    fontWeight: 600,
                    overflow: "hidden",
                    lineHeight: 1,
                    padding: size >= 32 ? "2px" : 0,
                    boxShadow: isFocused
                      ? "0 0 0 2px #00a3a6, 0 0 0 3px #fff"
                      : "none",
                    position: "relative",
                    zIndex: isFocused ? 2 : 1,
                  }}
                  title={sid ? `${wellLabel(r, c)} · ${sid}` : wellLabel(r, c)}
                >
                  {labelMode === "sample" && sid
                    ? (() => {
                        // Character budget calibrated against the chosen font
                        // size so even 8-char IDs like "sample10" fit cleanly.
                        const maxChars =
                          size >= 44 ? 8 : size >= 36 ? 6 : size >= 28 ? 4 : 3;
                        return sid.length > maxChars
                          ? sid.slice(0, maxChars - 1) + "…"
                          : sid;
                      })()
                    : labelMode === "well"
                      ? wellLabel(r, c)
                      : ""}
                </button>
              );
            })}
          </React.Fragment>
        ))}
      </div>
      {arrows && arrows.length > 0 && (
        <PlateArrowsOverlay
          arrows={arrows}
          rows={rows}
          cols={cols}
          size={size}
        />
      )}
    </div>
  );
};

/** Arrow overlay drawn absolutely over a PlateGrid. Coordinates are
    computed from the well indices: wells are `size` px each, separated by 2 px
    gap, and the grid has a `size` px header row and column. */
const PlateArrowsOverlay = ({ arrows, rows, cols, size }) => {
  const step = size + 2; // well + gap
  const totalW = step + cols * step;
  const totalH = step + rows * step;
  const wellCenter = (r, c) => ({
    x: step + c * step + size / 2,
    y: step + r * step + size / 2,
  });

  // Unique marker id per color so arrowheads pick up the right tint
  const colorsUsed = Array.from(new Set(arrows.map((a) => a.color)));
  const markerId = (c) => `arr-${c.replace("#", "")}`;

  return (
    <svg
      width={totalW}
      height={totalH}
      style={{
        position: "absolute",
        top: 0,
        left: 0,
        pointerEvents: "none",
        zIndex: 3,
      }}
    >
      <defs>
        {colorsUsed.map((color) => (
          <marker
            key={color}
            id={markerId(color)}
            viewBox="0 0 10 10"
            refX="8"
            refY="5"
            markerWidth="5"
            markerHeight="5"
            orient="auto-start-reverse"
          >
            <path d="M 0 0 L 10 5 L 0 10 z" fill={color} />
          </marker>
        ))}
      </defs>
      {arrows.map((a) => {
        const p1 = wellCenter(a.fromRow, a.fromCol);
        const p2 = wellCenter(a.toRow, a.toCol);
        const dx = p2.x - p1.x;
        const dy = p2.y - p1.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        // Pull line endpoints in so arrows don't start/end inside the wells
        const inset = size / 2 - 1;
        const ux = dx / (dist || 1);
        const uy = dy / (dist || 1);
        const sx = p1.x + ux * inset;
        const sy = p1.y + uy * inset;
        const ex = p2.x - ux * inset;
        const ey = p2.y - uy * inset;

        // Quadratic bezier control point perpendicular to line,
        // to separate overlapping arrows between neighboring wells
        const mx = (sx + ex) / 2;
        const my = (sy + ey) / 2;
        const curvature = Math.min(dist * 0.15, size * 0.9);
        // perpendicular unit vector (rotate 90°)
        const px = -uy;
        const py = ux;
        const cx = mx + px * curvature;
        const cy = my + py * curvature;

        return (
          <path
            key={a.key}
            d={`M ${sx} ${sy} Q ${cx} ${cy} ${ex} ${ey}`}
            fill="none"
            stroke={a.color}
            strokeWidth={a.width || 1.5}
            strokeOpacity={a.opacity ?? 1}
            strokeLinecap="round"
            markerEnd={`url(#${markerId(a.color)})`}
          />
        );
      })}
    </svg>
  );
};
