/* ---------- generic upload card ---------- */
const UploadCard = ({
  label,
  hint,
  filename,
  onFile,
  primary,
  inputRef,
  onDownload,
  onClear,
  info,
}) => {
  const [drag, setDrag] = useState(false);
  const loaded = !!filename;

  const handleClear = () => {
    if (!onClear) return;
    if (
      window.confirm(
        `Remove the loaded ${label}?\n\nThis only clears it from this browser session — your original file on disk is untouched.`,
      )
    ) {
      onClear();
    }
  };

  return (
    <div
      onDragOver={(e) => {
        e.preventDefault();
        setDrag(true);
      }}
      onDragLeave={() => setDrag(false)}
      onDrop={(e) => {
        e.preventDefault();
        setDrag(false);
        if (e.dataTransfer.files?.[0]) onFile(e.dataTransfer.files[0]);
      }}
      className="px-4 py-4 flex items-center gap-4 rounded-sm"
      style={{
        border: drag
          ? "2px dashed #00a3a6"
          : loaded
            ? "2px solid #00a3a6"
            : "2px dashed #c4c0b3",
        background: loaded ? "#fff" : "#fafbfb",
      }}
    >
      <div
        className="w-11 h-11 flex items-center justify-center rounded-sm"
        style={{ background: loaded ? "#00a3a6" : "#275662", color: "white" }}
      >
        {loaded ? <CheckCircle2 className="w-5 h-5" /> : <Upload className="w-5 h-5" />}
      </div>
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2 flex-wrap">
          <span
            className="text-[14px]"
            style={{
              color: "#275662",
              fontWeight: 700,
              fontFamily: '"Raleway", sans-serif',
            }}
          >
            {label}
          </span>
          {info && <InfoTooltip side="bottom">{info}</InfoTooltip>}
          {primary && <Pill tone="ink">required</Pill>}
        </div>
        <div className="text-[12px] text-stone-600 mt-0.5">{hint}</div>
        {loaded && (
          <div
            className="text-[12px] mt-1"
            style={{
              color: "#00a3a6",
              fontWeight: 600,
              fontFamily: '"Raleway", sans-serif',
            }}
          >
            ✓ {filename}
          </div>
        )}
      </div>
      <input
        ref={inputRef}
        type="file"
        accept=".tsv,.txt,.csv,.tab"
        className="hidden"
        onChange={(e) => e.target.files?.[0] && onFile(e.target.files[0])}
      />
      <div className="flex flex-col items-stretch gap-1.5 shrink-0">
        <button
          onClick={() => inputRef.current?.click()}
          className="px-4 py-2 text-[12px] rounded-sm"
          style={{
            background: "#275662",
            color: "white",
            fontWeight: 700,
            letterSpacing: "0.02em",
            fontFamily: '"Raleway", sans-serif',
          }}
          onMouseOver={(e) => (e.currentTarget.style.background = "#00a3a6")}
          onMouseOut={(e) => (e.currentTarget.style.background = "#275662")}
        >
          {loaded ? "Replace" : "Browse"}
        </button>
        {loaded && onDownload && (
          <button
            onClick={onDownload}
            title="Download this file"
            className="px-2 py-1 text-[11px] rounded-sm flex items-center justify-center gap-1"
            style={{
              background: "#fff",
              color: "#275662",
              border: "1px solid #c4c0b3",
              fontWeight: 600,
              fontFamily: '"Raleway", sans-serif',
            }}
            onMouseOver={(e) => {
              e.currentTarget.style.borderColor = "#00a3a6";
              e.currentTarget.style.color = "#00a3a6";
            }}
            onMouseOut={(e) => {
              e.currentTarget.style.borderColor = "#c4c0b3";
              e.currentTarget.style.color = "#275662";
            }}
          >
            <Download className="w-3 h-3" />
            Download
          </button>
        )}
        {loaded && onClear && (
          <button
            onClick={handleClear}
            title="Remove this file from the session"
            className="px-2 py-1 text-[11px] rounded-sm flex items-center justify-center gap-1"
            style={{
              background: "#fff",
              color: "#797870",
              border: "1px solid #e6e8e8",
              fontWeight: 600,
              fontFamily: '"Raleway", sans-serif',
            }}
            onMouseOver={(e) => {
              e.currentTarget.style.borderColor = "#ed6e6c";
              e.currentTarget.style.color = "#ed6e6c";
            }}
            onMouseOut={(e) => {
              e.currentTarget.style.borderColor = "#e6e8e8";
              e.currentTarget.style.color = "#797870";
            }}
          >
            <X className="w-3 h-3" />
            Clear
          </button>
        )}
      </div>
    </div>
  );
};

/* ---------- metadata / plate specialized upload cards ---------- */
const MetadataUploadCard = ({ metadata, setMetadata, setErr }) => {
  const inputRef = useRef(null);
  const onFile = async (file) => {
    try {
      const text = await file.text();
      setMetadata(parseMetadata(text));
      setErr(null);
    } catch (e) {
      setErr(`Metadata: ${e.message}`);
    }
  };
  return (
    <UploadCard
      label="metadata.tsv"
      hint="Optional — adds sample context (biome, controls, low biomass, related samples)"
      filename={metadata ? `${metadata.nSamples} samples annotated` : null}
      onFile={onFile}
      inputRef={inputRef}
      info={
        <>
          <div style={{ fontWeight: 700, marginBottom: 4 }}>
            Sample annotations (TSV)
          </div>
          Mandatory:{" "}
          <code style={{ fontFamily: "ui-monospace, monospace" }}>
            sample_id
          </code>
          . Recognized columns:{" "}
          <code style={{ fontFamily: "ui-monospace, monospace" }}>
            subject_id
          </code>
          ,{" "}
          <code style={{ fontFamily: "ui-monospace, monospace" }}>
            timepoint
          </code>
          ,{" "}
          <code style={{ fontFamily: "ui-monospace, monospace" }}>biome</code>
          ,{" "}
          <code style={{ fontFamily: "ui-monospace, monospace" }}>
            low_biomass
          </code>
          ,{" "}
          <code style={{ fontFamily: "ui-monospace, monospace" }}>
            group_id
          </code>
          . Any other column is shown as a generic key:value pill. See the
          Help tab for accepted aliases (family_id, cage_id, host, etc.).
        </>
      }
      onDownload={
        metadata
          ? () => downloadText(metadataToTSV(metadata), "metadata.tsv")
          : undefined
      }
      onClear={metadata ? () => setMetadata(null) : undefined}
    />
  );
};

const PlateUploadCard = ({ plateMap, setPlateMap, setErr }) => {
  const inputRef = useRef(null);
  const onFile = async (file) => {
    try {
      const text = await file.text();
      setPlateMap(parsePlateMap(text));
      setErr(null);
    } catch (e) {
      setErr(`Plate map: ${e.message}`);
    }
  };
  return (
    <UploadCard
      label="plate_map.tsv"
      hint="Optional — enables plate view and proximity criteria"
      filename={
        plateMap
          ? `${Object.keys(plateMap.bySample).length} wells (${plateMap.format.rows}×${plateMap.format.cols})`
          : null
      }
      onFile={onFile}
      inputRef={inputRef}
      info={
        <>
          <div style={{ fontWeight: 700, marginBottom: 4 }}>
            Sample-to-well placement (TSV)
          </div>
          Three columns:{" "}
          <code style={{ fontFamily: "ui-monospace, monospace" }}>
            sample_id
          </code>
          ,{" "}
          <code style={{ fontFamily: "ui-monospace, monospace" }}>plate</code>
          ,{" "}
          <code style={{ fontFamily: "ui-monospace, monospace" }}>well</code>
          . Wells use letter-then-number coordinates (A01–H12 for 96-well,
          A01–P24 for 384-well). Plate format is auto-detected. Loading this
          unlocks the Plate map tab and the "Proximity on plate" criterion.
        </>
      }
      onDownload={
        plateMap
          ? () => downloadText(plateMapToTSV(plateMap), "plate_map.tsv")
          : undefined
      }
      onClear={plateMap ? () => setPlateMap(null) : undefined}
    />
  );
};

