/* ---------- SCATTER TAB ---------- */
/* ----- Mini scatter thumbnail (for the gallery) ----- */
const MiniScatter = ({ scatter, width = 220, height = 180 }) => {
  if (!scatter) return null;
  const pad = { l: 8, r: 8, t: 8, b: 8 };
  const w = width - pad.l - pad.r;
  const h = height - pad.t - pad.b;
  if (scatter.error) {
    return (
      <div
        style={{
          width,
          height,
          background: "#fdeceb",
          border: "1px solid #ed6e6c",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          color: "#8a2422",
          fontSize: 10,
          textAlign: "center",
          padding: 8,
          lineHeight: 1.3,
        }}
      >
        sample name not found in abundance table
      </div>
    );
  }
  const floor = 1e-8;
  const pts = scatter.points.map((p) => ({
    ...p,
    lx: Math.log10(Math.max(p.x, floor)),
    ly: Math.log10(Math.max(p.y, floor)),
  }));
  if (pts.length === 0) {
    return (
      <div
        style={{
          width,
          height,
          background: "#fafbfb",
          border: "1px solid #e6e8e8",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          color: "#797870",
          fontSize: 11,
        }}
      >
        no data
      </div>
    );
  }
  const allX = pts.map((p) => p.lx);
  const allY = pts.map((p) => p.ly);
  const lo = Math.floor(Math.min(Math.log10(floor), ...allX, ...allY));
  const hi = Math.ceil(Math.max(...allX, ...allY, -2));
  const sx = (v) => pad.l + ((v - lo) / (hi - lo)) * w;
  const sy = (v) => pad.t + h - ((v - lo) / (hi - lo)) * h;
  return (
    <svg width={width} height={height} style={{ display: "block", background: "#fff" }}>
      {/* axes */}
      <line
        x1={pad.l}
        y1={pad.t + h}
        x2={pad.l + w}
        y2={pad.t + h}
        stroke="#c4c0b3"
        strokeWidth="0.75"
      />
      <line
        x1={pad.l}
        y1={pad.t}
        x2={pad.l}
        y2={pad.t + h}
        stroke="#c4c0b3"
        strokeWidth="0.75"
      />
      {/* contamination line */}
      {scatter.logC != null && (
        <line
          x1={sx(lo)}
          y1={sy(lo - scatter.logC)}
          x2={sx(hi)}
          y2={sy(hi - scatter.logC)}
          stroke="#ed6e6c"
          strokeWidth="1"
          strokeDasharray="3 2"
        />
      )}
      {/* points */}
      {pts.map((p, i) => (
        <circle
          key={i}
          cx={sx(p.lx)}
          cy={sy(p.ly)}
          r={p.onLine ? 2 : 1.4}
          fill={p.onLine ? "#ed6e6c" : "#275662"}
          fillOpacity={p.onLine ? 0.9 : 0.35}
        />
      ))}
      {/* y=x identity (drawn last so it stays on top) */}
      <line
        x1={sx(lo)}
        y1={sy(lo)}
        x2={sx(hi)}
        y2={sy(hi)}
        stroke="#000000"
        strokeWidth="0.7"
        strokeDasharray="1.5 2.5"
        strokeOpacity="0.7"
      />
    </svg>
  );
};

/* ----- Gallery card ----- */
const GalleryCard = ({ event, ab, metadata, plateMap, onPick }) => {
  const scatter = useMemo(() => buildScatter(ab, event), [ab, event]);
  const related = areRelated(metadata, event.source, event.target);
  const pd = plateDistance(plateMap, event.source, event.target);
  const verdictDot =
    event.verdict === "true_positive" ? "#00a3a6" :
    event.verdict === "false_positive" ? "#ed6e6c" :
    event.verdict === "uncertain" ? "#c4c0b3" : null;

  return (
    <button
      onClick={() => onPick(event.id)}
      className="text-left rounded-sm"
      style={{
        border: "1px solid #e6e8e8",
        background: "#fff",
        transition: "transform 0.12s, box-shadow 0.12s, border-color 0.12s",
        padding: 0,
        overflow: "hidden",
        width: "100%",
      }}
      onMouseEnter={(e) => {
        e.currentTarget.style.transform = "translateY(-2px)";
        e.currentTarget.style.boxShadow = "0 6px 14px -6px rgba(39, 86, 98, 0.25)";
        e.currentTarget.style.borderColor = "#00a3a6";
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.transform = "";
        e.currentTarget.style.boxShadow = "";
        e.currentTarget.style.borderColor = "#e6e8e8";
      }}
    >
      <div style={{ background: "#fff", borderBottom: "1px solid #f0f2f2" }}>
        <MiniScatter scatter={scatter} width={240} height={180} />
      </div>
      <div style={{ padding: "10px 12px" }}>
        <div className="flex items-center gap-1.5 mb-1">
          {verdictDot && (
            <span
              className="w-2 h-2 rounded-full shrink-0"
              style={{ background: verdictDot }}
            />
          )}
          <div
            className="text-[12px] truncate"
            style={{
              color: "#275662",
              fontWeight: 700,
              fontFamily: '"Raleway", sans-serif',
            }}
          >
            {event.source} → {event.target}
          </div>
        </div>
        <div
          className="flex items-center justify-between text-[11px] tabular mb-2"
          style={{ color: "#797870" }}
        >
          <span>
            probability <b style={{ color: "#275662" }}>{event.score.toFixed(3)}</b>
          </span>
          <span>
            rate{" "}
            <b style={{ color: "#275662" }}>
              {(event.rate * 100).toFixed(2)}%
            </b>
          </span>
        </div>
        {(related?.related === true ||
          (pd && pd.samePlate && pd.distance != null && pd.distance <= 2) ||
          event.cascade) && (
          <div className="flex flex-wrap gap-1">
            {related?.related === true && (
              <Pill tone="warn">
                {related.kind === "group" ? "same group" : "related"}
              </Pill>
            )}
            {pd && pd.samePlate && pd.distance != null && pd.distance <= 1 && (
              <Pill tone="bad">adjacent</Pill>
            )}
            {pd && pd.samePlate && pd.distance === 2 && (
              <Pill tone="warn">Δ=2</Pill>
            )}
            {event.cascade && <Pill tone="violet">cascade</Pill>}
          </div>
        )}
      </div>
    </button>
  );
};

/* ----- Scatterplot gallery tab ----- */
const ScatterTab = ({ events, ab, metadata, plateMap, onPick }) => {
  const [sortBy, setSortBy] = useState("score");

  if (!ab) {
    return (
      <div>
        <SectionTitle eyebrow="Scatterplots" title="Event gallery">
          Browse every flagged event as a scatterplot thumbnail. Click any card
          to open it in the Guided validation workflow.
        </SectionTitle>
        <div
          className="p-6 rounded-sm"
          style={{ background: "#fdeceb", border: "1px solid #ed6e6c", color: "#8a2422" }}
        >
          <strong>Scatterplots require the abundance table.</strong> Drop{" "}
          <code>species_abundance.tsv</code> above to enable this view.
        </div>
      </div>
    );
  }

  const sorted = useMemo(() => {
    const copy = [...events];
    if (sortBy === "score") copy.sort((a, b) => b.score - a.score);
    else if (sortBy === "rate") copy.sort((a, b) => b.rate - a.rate);
    else if (sortBy === "pending") {
      const rank = (v) =>
        v === "pending" ? 0 : v === "uncertain" ? 1 : v === "true_positive" ? 2 : 3;
      copy.sort((a, b) => rank(a.verdict) - rank(b.verdict) || b.score - a.score);
    } else if (sortBy === "source") {
      copy.sort((a, b) => a.source.localeCompare(b.source));
    }
    return copy;
  }, [events, sortBy]);

  return (
    <div>
      <SectionTitle eyebrow="Scatterplots" title="Event gallery">
        Browse every flagged event as a scatterplot thumbnail. Click any card
        to open it in the Guided validation workflow for full diagnostics.
      </SectionTitle>

      <div className="flex items-center gap-3 mb-6 flex-wrap">
        <span
          className="text-[11px] uppercase tracking-[0.1em]"
          style={{
            color: "#797870",
            fontWeight: 700,
            fontFamily: '"Raleway", sans-serif',
          }}
        >
          Sort by
        </span>
        {[
          { id: "score", label: "probability" },
          { id: "rate", label: "rate" },
          { id: "pending", label: "pending first" },
          { id: "source", label: "source" },
        ].map((opt) => {
          const active = sortBy === opt.id;
          return (
            <button
              key={opt.id}
              onClick={() => setSortBy(opt.id)}
              className="px-3 py-1 text-[11px] rounded-sm"
              style={{
                background: active ? "#275662" : "#fff",
                color: active ? "#fff" : "#275662",
                border: "1px solid #275662",
                fontWeight: 600,
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              {opt.label}
            </button>
          );
        })}
        <span className="ml-auto text-[12px]" style={{ color: "#797870" }}>
          {sorted.length} event{sorted.length !== 1 ? "s" : ""}
        </span>
      </div>

      <div
        className="grid gap-4"
        style={{
          gridTemplateColumns: "repeat(auto-fill, minmax(240px, 1fr))",
        }}
      >
        {sorted.map((e) => (
          <GalleryCard
            key={e.id}
            event={e}
            ab={ab}
            metadata={metadata}
            plateMap={plateMap}
            onPick={onPick}
          />
        ))}
      </div>

      <p className="text-[11px] mt-6" style={{ color: "#797870" }}>
        Click any thumbnail to open the full view with diagnostics and verdict
        controls.
      </p>
    </div>
  );
};

/* ---------- NETWORK TAB ---------- */
const NetworkTab = ({ events, onPick }) => (
  <div>
    <SectionTitle eyebrow="Network" title="Contamination map">
      Directed graph from source to target. Edge thickness and color intensity
      reflect the contamination rate (log-scaled — heavier, darker arrows mean
      higher rates). Salmon nodes appear on both sides — a possible
      contamination cascade. Hover any edge for details, click to open it in
      Guided validation.
    </SectionTitle>
    <NetworkGraph events={events} onPick={onPick} />
    <p
      className="text-[11px] mt-3 flex items-center gap-1.5"
      style={{ color: "#797870" }}
    >
      <span
        className="inline-block w-2 h-2 rounded-full"
        style={{ background: "#00a3a6" }}
      />
      Hover an edge to inspect it, click to jump into validation. Scroll to
      zoom in on dense clusters, drag the background to pan.
    </p>
  </div>
);
/* ---------- PLATE TAB ---------- */
const PlateEditor = ({ samples, plateMap, setPlateMap }) => {
  const [format, setFormat] = useState(
    plateMap?.format || { rows: 8, cols: 12 },
  );
  const [plateId, setPlateId] = useState(
    plateMap ? Object.values(plateMap.bySample)[0]?.plate || "P1" : "P1",
  );
  const [selectedSample, setSelectedSample] = useState(null);
  const [sampleQuery, setSampleQuery] = useState("");
  const [showUnplacedOnly, setShowUnplacedOnly] = useState(false);
  const [focus, setFocus] = useState({ row: 0, col: 0 });
  const gridRef = useRef(null);

  const placed = useMemo(() => {
    const s = new Set();
    if (plateMap) Object.keys(plateMap.bySample).forEach((id) => s.add(id));
    return s;
  }, [plateMap]);

  const unplaced = useMemo(
    () => samples.filter((s) => !placed.has(s)),
    [samples, placed],
  );

  const filteredSamples = useMemo(() => {
    let list = showUnplacedOnly ? unplaced : samples;
    if (sampleQuery.trim()) {
      const q = sampleQuery.toLowerCase().trim();
      list = list.filter((s) => s.toLowerCase().includes(q));
    }
    return list;
  }, [samples, unplaced, showUnplacedOnly, sampleQuery]);

  /** Place `sid` (or the currently-selected sample) in well (r, c). */
  const placeSample = (r, c, sid = selectedSample) => {
    if (!sid) return;
    const newMap = { ...(plateMap?.bySample || {}) };
    // remove any previous placement of this sample
    delete newMap[sid];
    // remove whatever was in this well
    Object.entries(newMap).forEach(([k, v]) => {
      if (v.plate === plateId && v.row === r && v.col === c) {
        delete newMap[k];
      }
    });
    newMap[sid] = { plate: plateId, row: r, col: c };
    setPlateMap({ bySample: newMap, format });
    setSelectedSample(null);
    // auto-advance the focus to the next empty well
    advanceFocusToNextEmpty({ bySample: newMap }, r, c);
  };

  const clearWell = (sid) => {
    const newMap = { ...(plateMap?.bySample || {}) };
    delete newMap[sid];
    setPlateMap(
      Object.keys(newMap).length ? { bySample: newMap, format } : null,
    );
  };

  /** Get the sample id currently at (plateId, row, col) if any. */
  const sampleAt = (r, c) => {
    if (!plateMap) return null;
    const hit = Object.entries(plateMap.bySample).find(
      ([, v]) => v.plate === plateId && v.row === r && v.col === c,
    );
    return hit ? hit[0] : null;
  };

  /** Move the keyboard focus to the next empty well, row-major. */
  const advanceFocusToNextEmpty = (map, fromR, fromC) => {
    const total = format.rows * format.cols;
    let idx = fromR * format.cols + fromC + 1;
    for (let k = 0; k < total; k++) {
      const r = Math.floor(idx / format.cols) % format.rows;
      const c = idx % format.cols;
      const occupied = Object.values(map.bySample || {}).some(
        (v) => v.plate === plateId && v.row === r && v.col === c,
      );
      if (!occupied) {
        setFocus({ row: r, col: c });
        return;
      }
      idx++;
    }
  };

  /** Keyboard navigation handler. */
  useEffect(() => {
    const el = gridRef.current;
    if (!el) return;
    const onKey = (e) => {
      // Only trap keys when the focus is within the editor container
      if (!el.contains(document.activeElement) && document.activeElement !== document.body) {
        // if focused in an <input>, don't interfere
        if (document.activeElement && document.activeElement.tagName === "INPUT") return;
      }
      let handled = true;
      if (e.key === "ArrowRight") {
        setFocus((f) => ({ ...f, col: Math.min(format.cols - 1, f.col + 1) }));
      } else if (e.key === "ArrowLeft") {
        setFocus((f) => ({ ...f, col: Math.max(0, f.col - 1) }));
      } else if (e.key === "ArrowDown") {
        setFocus((f) => ({ ...f, row: Math.min(format.rows - 1, f.row + 1) }));
      } else if (e.key === "ArrowUp") {
        setFocus((f) => ({ ...f, row: Math.max(0, f.row - 1) }));
      } else if (e.key === "Enter") {
        if (selectedSample) placeSample(focus.row, focus.col);
      } else if (e.key === "Delete" || e.key === "Backspace") {
        const sid = sampleAt(focus.row, focus.col);
        if (sid) clearWell(sid);
      } else {
        handled = false;
      }
      if (handled) e.preventDefault();
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [focus, selectedSample, plateMap, plateId, format]);

  const downloadTSV = () => {
    if (!plateMap) return;
    const tsv = plateMapToTSV(plateMap);
    const blob = new Blob([tsv], { type: "text/tab-separated-values" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "plate_map.tsv";
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="lg:flex lg:gap-10 gap-8 flex-col lg:flex-row">
      <div ref={gridRef} tabIndex={0} style={{ outline: "none" }}>
        <div className="flex items-center gap-2 mb-3 flex-wrap">
          <label
            className="text-[11px]"
            style={{
              color: "#275662",
              fontWeight: 700,
              fontFamily: '"Raleway", sans-serif',
            }}
          >
            Format:
          </label>
          <select
            value={`${format.rows}x${format.cols}`}
            onChange={(e) => {
              const [r, c] = e.target.value.split("x").map(Number);
              setFormat({ rows: r, cols: c });
              if (plateMap)
                setPlateMap({ ...plateMap, format: { rows: r, cols: c } });
            }}
            className="px-2 py-1 text-[11px] rounded-sm"
            style={{ border: "1px solid #c4c0b3" }}
          >
            <option value="8x12">96-well (8×12)</option>
            <option value="16x24">384-well (16×24)</option>
          </select>
          <label
            className="text-[11px] ml-3"
            style={{
              color: "#275662",
              fontWeight: 700,
              fontFamily: '"Raleway", sans-serif',
            }}
          >
            Plate:
          </label>
          <input
            value={plateId}
            onChange={(e) => setPlateId(e.target.value)}
            className="px-2 py-1 text-[11px] rounded-sm w-20"
            style={{ border: "1px solid #c4c0b3" }}
          />
        </div>

        <PlateGrid
          format={format}
          plateId={plateId}
          plateMap={plateMap}
          highlightSamples={selectedSample ? { [selectedSample]: "#00a3a6" } : {}}
          onClickWell={(r, c) => {
            setFocus({ row: r, col: c });
            if (selectedSample) placeSample(r, c);
          }}
          focus={focus}
          editable
          labelMode="sample"
          size={format.rows > 8 ? 24 : 44}
        />

        {/* Keyboard shortcuts cheatsheet */}
        <div
          className="mt-3 p-2.5 rounded-sm text-[11px]"
          style={{
            background: "#f6f7f7",
            border: "1px solid #e6e8e8",
            color: "#275662",
          }}
        >
          <span
            className="uppercase tracking-[0.1em] mr-2"
            style={{
              color: "#ed6e6c",
              fontWeight: 700,
              fontFamily: '"Raleway", sans-serif',
              fontSize: 10,
            }}
          >
            Shortcuts
          </span>
          <kbd style={kbdStyle}>←↑→↓</kbd> move focus ·{" "}
          <kbd style={kbdStyle}>Enter</kbd> place selected sample ·{" "}
          <kbd style={kbdStyle}>Del</kbd> clear well
        </div>

        <div className="mt-4 flex gap-2">
          <button
            onClick={downloadTSV}
            disabled={!plateMap}
            className="px-3 py-1.5 text-[11px] rounded-sm"
            style={{
              background: "#275662",
              color: "#fff",
              fontWeight: 700,
              opacity: !plateMap ? 0.4 : 1,
              fontFamily: '"Raleway", sans-serif',
            }}
          >
            <Download className="w-3 h-3 inline mr-1" />
            Export plate map
          </button>
          <button
            onClick={() => setPlateMap(null)}
            disabled={!plateMap}
            className="px-3 py-1.5 text-[11px] rounded-sm"
            style={{
              background: "#fff",
              color: "#275662",
              fontWeight: 700,
              border: "1px solid #c4c0b3",
              opacity: !plateMap ? 0.4 : 1,
              fontFamily: '"Raleway", sans-serif',
            }}
          >
            Clear all
          </button>
        </div>
      </div>

      <div className="lg:w-[480px] lg:flex-shrink-0">
        <div
          className="text-[10px] tracking-[0.15em] uppercase mb-3"
          style={{
            color: "#ed6e6c",
            fontWeight: 700,
            fontFamily: '"Raleway", sans-serif',
          }}
        >
          Samples {selectedSample ? "— click a well (or press Enter) to place" : ""}
        </div>

        {/* Filter controls */}
        <div className="flex items-center gap-2 mb-3 flex-wrap">
          <div className="relative flex-1 min-w-[180px]">
            <Search
              className="absolute left-2 top-1/2 -translate-y-1/2 w-3.5 h-3.5"
              style={{ color: "#797870" }}
            />
            <input
              value={sampleQuery}
              onChange={(e) => setSampleQuery(e.target.value)}
              placeholder="search sample…"
              className="pl-7 pr-3 py-1.5 text-[12px] rounded-sm w-full outline-none"
              style={{ border: "1px solid #c4c0b3" }}
            />
          </div>
          <label
            className="flex items-center gap-1.5 text-[12px] cursor-pointer"
            style={{ color: "#275662" }}
          >
            <input
              type="checkbox"
              checked={showUnplacedOnly}
              onChange={(e) => setShowUnplacedOnly(e.target.checked)}
              style={{ accentColor: "#00a3a6" }}
            />
            unplaced only
          </label>
        </div>

        <div className="mb-3 text-[12px]" style={{ color: "#797870" }}>
          {unplaced.length} unplaced · {placed.size} placed of {samples.length}
          {sampleQuery && (
            <>
              {" "}· {filteredSamples.length} matching
            </>
          )}
        </div>

        <div
          className="rounded-sm max-h-[520px] overflow-auto"
          style={{ border: "1px solid #e6e8e8" }}
        >
          {filteredSamples.map((s) => {
            const pos = plateMap?.bySample[s];
            const isSelected = selectedSample === s;
            return (
              <div
                key={s}
                className="px-3 py-2 text-[12px] flex items-center gap-2"
                style={{
                  borderBottom: "1px solid #f0f2f2",
                  background: isSelected
                    ? "#00a3a6"
                    : pos
                      ? "#f6f7f7"
                      : "#fff",
                  color: isSelected ? "#fff" : "#275662",
                }}
              >
                <button
                  onClick={() => setSelectedSample(isSelected ? null : s)}
                  className="flex-1 text-left"
                  style={{ fontWeight: 600 }}
                >
                  {s}
                </button>
                {pos ? (
                  <>
                    <Pill tone={isSelected ? "ink" : "primary"}>
                      {pos.plate} · {wellLabel(pos.row, pos.col)}
                    </Pill>
                    <button
                      onClick={() => clearWell(s)}
                      title="remove"
                      style={{ color: isSelected ? "#fff" : "#797870" }}
                    >
                      <X className="w-3 h-3" />
                    </button>
                  </>
                ) : (
                  <Pill tone={isSelected ? "ink" : "neutral"}>to place</Pill>
                )}
              </div>
            );
          })}
          {filteredSamples.length === 0 && (
            <div
              className="px-3 py-6 text-center text-[12px]"
              style={{ color: "#797870" }}
            >
              No samples match this filter.
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const kbdStyle = {
  display: "inline-block",
  padding: "1px 6px",
  margin: "0 2px",
  background: "#fff",
  border: "1px solid #c4c0b3",
  borderRadius: 3,
  fontFamily: "system-ui, monospace",
  fontSize: 10,
  fontWeight: 600,
  color: "#275662",
};

/* ---------- PLATE THUMBNAIL (for overview grid) ---------- */
const PlateThumbnail = ({
  plate,
  plateMap,
  eventsBySample,
  selectedEventWells,
  onClick,
}) => {
  // Compute which wells are occupied and whether they belong to an event
  const rows = plateMap.format.rows;
  const cols = plateMap.format.cols;
  const cellSize = 7; // px — small enough for dozens of thumbnails
  const padding = 4;
  const width = cols * cellSize + padding * 2;
  const height = rows * cellSize + padding * 2;

  const grid = useMemo(() => {
    const g = {};
    Object.entries(plateMap.bySample).forEach(([sid, p]) => {
      if (p.plate !== plate.id) return;
      g[`${p.row}-${p.col}`] = sid;
    });
    return g;
  }, [plateMap, plate.id]);

  return (
    <button
      onClick={onClick}
      className="rounded-sm text-left"
      style={{
        border: "1px solid #e6e8e8",
        background: "#fff",
        padding: 12,
        transition:
          "transform 0.12s, box-shadow 0.12s, border-color 0.12s",
        cursor: "pointer",
      }}
      onMouseEnter={(e) => {
        e.currentTarget.style.transform = "translateY(-2px)";
        e.currentTarget.style.boxShadow =
          "0 6px 14px -6px rgba(39,86,98,0.25)";
        e.currentTarget.style.borderColor = "#00a3a6";
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.transform = "";
        e.currentTarget.style.boxShadow = "";
        e.currentTarget.style.borderColor = "#e6e8e8";
      }}
    >
      <svg
        width={width}
        height={height}
        style={{ display: "block", margin: "0 auto" }}
      >
        <rect
          x="0"
          y="0"
          width={width}
          height={height}
          fill="#fafbfb"
          stroke="#e6e8e8"
          strokeWidth="1"
          rx="2"
        />
        {Array.from({ length: rows }).map((_, r) =>
          Array.from({ length: cols }).map((_, c) => {
            const sid = grid[`${r}-${c}`];
            const hasEvent = sid && eventsBySample[sid];
            const selected = sid && selectedEventWells?.has(sid);
            let fill = "#e6e8e8"; // empty well
            if (sid) fill = "#c9dfe0"; // placed
            if (hasEvent) fill = "#ed6e6c"; // contamination
            if (selected) fill = "#00a3a6"; // currently-picked event
            return (
              <circle
                key={`${r}-${c}`}
                cx={padding + c * cellSize + cellSize / 2}
                cy={padding + r * cellSize + cellSize / 2}
                r={cellSize / 2 - 0.5}
                fill={fill}
              />
            );
          }),
        )}
      </svg>
      <div
        className="mt-2 text-[13px] truncate"
        style={{
          color: "#275662",
          fontWeight: 700,
          fontFamily: '"Raleway", sans-serif',
        }}
      >
        {plate.id}
      </div>
      <div
        className="text-[11px] tabular flex items-center justify-between mt-0.5"
        style={{ color: "#797870" }}
      >
        <span>
          {plate.nSamples} sample{plate.nSamples !== 1 ? "s" : ""}
        </span>
        <span>
          <span style={{ color: plate.nEvents ? "#ed6e6c" : "#797870", fontWeight: 600 }}>
            {plate.nEvents}
          </span>{" "}
          event{plate.nEvents !== 1 ? "s" : ""}
        </span>
      </div>
      {plate.nAdjacent > 0 && (
        <div
          className="mt-1 text-[10px]"
          style={{ color: "#8a2422", fontWeight: 600 }}
        >
          {plate.nAdjacent} adjacent-well
        </div>
      )}
    </button>
  );
};

/* ---------- PLATE TAB ---------- */
const PlateTab = ({ events, plateMap, setPlateMap, samples, onPick }) => {
  const [mode, setMode] = useState(plateMap ? "overview" : "edit");
  const [currentPlate, setCurrentPlate] = useState(null);
  const [hoverEvent, setHoverEvent] = useState(null);
  const [plateFilter, setPlateFilter] = useState("all"); // all | withEvents
  const [eventFilter, setEventFilter] = useState("all"); // all | thisPlate | interPlate | adjacent
  const [showArrows, setShowArrows] = useState(false);

  const plates = useMemo(() => {
    if (!plateMap) return [];
    const s = new Set();
    Object.values(plateMap.bySample).forEach((p) => s.add(p.plate));
    return Array.from(s).sort();
  }, [plateMap]);

  // Compute per-plate stats once for all views
  const plateStats = useMemo(() => {
    if (!plateMap) return [];
    const samplesByPlate = {};
    plates.forEach((p) => (samplesByPlate[p] = 0));
    Object.values(plateMap.bySample).forEach((p) => {
      samplesByPlate[p.plate] = (samplesByPlate[p.plate] || 0) + 1;
    });

    const eventsByPlate = {};
    const adjByPlate = {};
    plates.forEach((p) => {
      eventsByPlate[p] = 0;
      adjByPlate[p] = 0;
    });
    events.forEach((e) => {
      const a = plateMap.bySample[e.source];
      const b = plateMap.bySample[e.target];
      if (!a || !b) return;
      const platesInvolved = new Set([a.plate, b.plate]);
      platesInvolved.forEach((pl) => {
        eventsByPlate[pl] = (eventsByPlate[pl] || 0) + 1;
      });
      if (a.plate === b.plate) {
        const d = Math.max(
          Math.abs(a.row - b.row),
          Math.abs(a.col - b.col),
        );
        if (d <= 1) adjByPlate[a.plate] = (adjByPlate[a.plate] || 0) + 1;
      }
    });

    return plates.map((p) => ({
      id: p,
      nSamples: samplesByPlate[p] || 0,
      nEvents: eventsByPlate[p] || 0,
      nAdjacent: adjByPlate[p] || 0,
    }));
  }, [plates, events, plateMap]);

  // For thumbnails: which samples participate in any event
  const eventsBySample = useMemo(() => {
    const m = {};
    events.forEach((e) => {
      m[e.source] = true;
      m[e.target] = true;
    });
    return m;
  }, [events]);

  // Inter-plate event count
  const interPlateCount = useMemo(() => {
    if (!plateMap) return 0;
    return events.filter((e) => {
      const a = plateMap.bySample[e.source];
      const b = plateMap.bySample[e.target];
      return a && b && a.plate !== b.plate;
    }).length;
  }, [events, plateMap]);

  const activePlate = currentPlate || plates[0];

  // For the inspect view: filter events for the list
  const filteredEvents = useMemo(() => {
    if (!plateMap) return [];
    return events
      .map((e) => {
        const a = plateMap.bySample[e.source];
        const b = plateMap.bySample[e.target];
        return { ...e, a, b };
      })
      .filter((e) => {
        if (!e.a || !e.b) return false;
        if (eventFilter === "thisPlate") {
          return e.a.plate === activePlate && e.b.plate === activePlate;
        }
        if (eventFilter === "interPlate") return e.a.plate !== e.b.plate;
        if (eventFilter === "adjacent") {
          if (e.a.plate !== e.b.plate) return false;
          const d = Math.max(
            Math.abs(e.a.row - e.b.row),
            Math.abs(e.a.col - e.b.col),
          );
          return d <= 1;
        }
        return e.a.plate === activePlate || e.b.plate === activePlate;
      });
  }, [events, plateMap, activePlate, eventFilter]);

  const highlightSamples = useMemo(() => {
    const h = {};
    if (hoverEvent) {
      h[hoverEvent.source] = "#00a3a6";
      h[hoverEvent.target] = "#ed6e6c";
    }
    return h;
  }, [hoverEvent]);

  // For thumbnails: which samples belong to the hovered event's plate
  const selectedEventWells = useMemo(() => {
    if (!hoverEvent) return null;
    const set = new Set();
    if (hoverEvent.source) set.add(hoverEvent.source);
    if (hoverEvent.target) set.add(hoverEvent.target);
    return set;
  }, [hoverEvent]);

  /** Arrows to draw over the current plate in Inspect mode.
      Colors: red = adjacent, orange = Δ=2, violet = cascade, grey = further.
      Opacity + width change on hover to emphasize the focused event. */
  const plateArrows = useMemo(() => {
    if (!plateMap || !showArrows) return null;
    const arrows = [];
    filteredEvents.forEach((e) => {
      // Only draw arrows for events fully within the active plate
      if (!e.a || !e.b) return;
      if (e.a.plate !== activePlate || e.b.plate !== activePlate) return;
      const d = Math.max(
        Math.abs(e.a.row - e.b.row),
        Math.abs(e.a.col - e.b.col),
      );
      let color = "#797870"; // grey (distant)
      if (e.cascade) color = "#423089"; // violet
      else if (d <= 1) color = "#ed6e6c"; // red adjacent
      else if (d === 2) color = "#e3a100"; // orange close
      const isHovered = hoverEvent && hoverEvent.id === e.id;
      const anyHover = !!hoverEvent;
      return arrows.push({
        key: `arr-${e.id}`,
        fromRow: e.a.row,
        fromCol: e.a.col,
        toRow: e.b.row,
        toCol: e.b.col,
        color,
        opacity: anyHover ? (isHovered ? 1 : 0.2) : 0.75,
        width: isHovered ? 2.5 : 1.5,
      });
    });
    // Render hovered arrow last so it draws on top
    arrows.sort((a, b) => (a.opacity < b.opacity ? -1 : 1));
    return arrows;
  }, [filteredEvents, plateMap, showArrows, activePlate, hoverEvent]);

  const visiblePlates = useMemo(() => {
    if (plateFilter === "withEvents") {
      return plateStats.filter((p) => p.nEvents > 0);
    }
    return plateStats;
  }, [plateStats, plateFilter]);

  return (
    <div>
      <SectionTitle eyebrow="Plate map" title="Physical proximity on the plate">
        Cross-sample (well-to-well) contamination happens between neighboring
        wells. Checking the geographic proximity of a source / target pair is
        one of the strongest diagnostic signals.
      </SectionTitle>

      {/* sub-mode selector */}
      <div className="flex gap-2 mb-4">
        {[
          { id: "overview", label: "Overview", disabledIfNoMap: true },
          { id: "inspect", label: "Inspect", disabledIfNoMap: true },
          { id: "edit", label: "Edit", disabledIfNoMap: false },
        ].map((m) => {
          const disabled = m.disabledIfNoMap && !plateMap;
          const active = mode === m.id;
          return (
            <button
              key={m.id}
              onClick={() => setMode(m.id)}
              disabled={disabled}
              className="px-4 py-1.5 text-[12px] rounded-sm"
              style={{
                background: active ? "#275662" : "#fff",
                color: active ? "#fff" : disabled ? "#c4c0b3" : "#275662",
                border: `1px solid ${disabled ? "#e6e8e8" : "#275662"}`,
                fontWeight: 700,
                fontFamily: '"Raleway", sans-serif',
                cursor: disabled ? "not-allowed" : "pointer",
              }}
            >
              {m.label}
            </button>
          );
        })}
      </div>

      {/* ============================================================
          OVERVIEW MODE
          ============================================================ */}
      {mode === "overview" && plateMap && (
        <>
          {/* Summary strip */}
          <div
            className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-6"
            style={{ maxWidth: 760 }}
          >
            <Stat label="Plates" value={plates.length} />
            <Stat
              label="Wells used"
              value={Object.keys(plateMap.bySample).length}
            />
            <Stat
              label="Events"
              value={events.length}
              tone={events.length > 0 ? "bad" : "neutral"}
            />
            <Stat
              label="Inter-plate events"
              value={interPlateCount}
              tone={interPlateCount > 0 ? "warn" : "neutral"}
            />
          </div>

          {/* Filter row */}
          <div className="flex items-center gap-3 mb-5 flex-wrap">
            <span
              className="text-[11px] uppercase tracking-[0.1em]"
              style={{
                color: "#797870",
                fontWeight: 700,
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              Show
            </span>
            {[
              { id: "all", label: `all plates (${plateStats.length})` },
              {
                id: "withEvents",
                label: `with events (${plateStats.filter((p) => p.nEvents > 0).length})`,
              },
            ].map((f) => {
              const active = plateFilter === f.id;
              return (
                <button
                  key={f.id}
                  onClick={() => setPlateFilter(f.id)}
                  className="px-3 py-1 text-[11px] rounded-sm"
                  style={{
                    background: active ? "#275662" : "#fff",
                    color: active ? "#fff" : "#275662",
                    border: "1px solid #275662",
                    fontWeight: 600,
                    fontFamily: '"Raleway", sans-serif',
                  }}
                >
                  {f.label}
                </button>
              );
            })}

            {/* legend */}
            <div
              className="ml-auto flex items-center gap-3 text-[11px]"
              style={{ color: "#797870" }}
            >
              <span className="flex items-center gap-1">
                <span
                  className="inline-block w-2.5 h-2.5 rounded-full"
                  style={{ background: "#c9dfe0" }}
                />
                occupied
              </span>
              <span className="flex items-center gap-1">
                <span
                  className="inline-block w-2.5 h-2.5 rounded-full"
                  style={{ background: "#ed6e6c" }}
                />
                event
              </span>
            </div>
          </div>

          {/* Thumbnail grid */}
          {visiblePlates.length === 0 ? (
            <div
              className="p-6 rounded-sm text-[13px] text-center"
              style={{
                background: "#f6f7f7",
                border: "1px solid #e6e8e8",
                color: "#797870",
              }}
            >
              No plates match this filter.
            </div>
          ) : (
            <div
              className="grid gap-3"
              style={{
                gridTemplateColumns:
                  "repeat(auto-fill, minmax(160px, 1fr))",
              }}
            >
              {visiblePlates.map((p) => (
                <PlateThumbnail
                  key={p.id}
                  plate={p}
                  plateMap={plateMap}
                  eventsBySample={eventsBySample}
                  selectedEventWells={null}
                  onClick={() => {
                    setCurrentPlate(p.id);
                    setMode("inspect");
                  }}
                />
              ))}
            </div>
          )}

          <p className="text-[11px] mt-6" style={{ color: "#797870" }}>
            Click any plate to open it in Inspect mode with the full grid and
            events list.
          </p>
        </>
      )}

      {/* ============================================================
          INSPECT MODE
          ============================================================ */}
      {mode === "inspect" && plateMap && plates.length > 0 && (
        <div className="lg:flex lg:gap-10 gap-8 flex-col lg:flex-row">
          <div>
            {/* Plate picker — pills for few, dropdown for many */}
            {plates.length > 1 && (
              <div className="mb-3">
                {plates.length <= 6 ? (
                  <div className="flex gap-1 flex-wrap">
                    {plates.map((p) => (
                      <button
                        key={p}
                        onClick={() => setCurrentPlate(p)}
                        className="px-3 py-1 text-[11px] rounded-sm"
                        style={{
                          background:
                            activePlate === p ? "#00a3a6" : "#f6f7f7",
                          color: activePlate === p ? "#fff" : "#275662",
                          fontWeight: 700,
                          border: "1px solid #e6e8e8",
                          fontFamily: '"Raleway", sans-serif',
                        }}
                      >
                        {p}
                      </button>
                    ))}
                  </div>
                ) : (
                  <div className="flex items-center gap-2">
                    <label
                      className="text-[11px]"
                      style={{
                        color: "#275662",
                        fontWeight: 700,
                        fontFamily: '"Raleway", sans-serif',
                      }}
                    >
                      Plate:
                    </label>
                    <select
                      value={activePlate}
                      onChange={(e) => setCurrentPlate(e.target.value)}
                      className="px-3 py-1 text-[12px] rounded-sm"
                      style={{
                        border: "1px solid #275662",
                        background: "#fff",
                        color: "#275662",
                        fontWeight: 700,
                        fontFamily: '"Raleway", sans-serif',
                        minWidth: 160,
                      }}
                    >
                      {plateStats.map((p) => (
                        <option key={p.id} value={p.id}>
                          {p.id} ({p.nEvents} event{p.nEvents !== 1 ? "s" : ""})
                        </option>
                      ))}
                    </select>
                    <button
                      onClick={() => setMode("overview")}
                      className="px-3 py-1 text-[11px] rounded-sm"
                      style={{
                        background: "#fff",
                        color: "#275662",
                        border: "1px solid #c4c0b3",
                        fontWeight: 600,
                        fontFamily: '"Raleway", sans-serif',
                      }}
                    >
                      ← Overview
                    </button>
                  </div>
                )}
              </div>
            )}

            {/* Main plate + possibly a second plate for inter-plate events */}
            {hoverEvent &&
            hoverEvent.a &&
            hoverEvent.b &&
            hoverEvent.a.plate !== hoverEvent.b.plate ? (
              <div className="flex gap-6 items-start flex-wrap">
                <div>
                  <div
                    className="text-[10px] mb-1 uppercase tracking-[0.1em]"
                    style={{
                      color: "#00a3a6",
                      fontWeight: 700,
                      fontFamily: '"Raleway", sans-serif',
                    }}
                  >
                    source — {hoverEvent.a.plate}
                  </div>
                  <PlateGrid
                    format={plateMap.format}
                    plateId={hoverEvent.a.plate}
                    plateMap={plateMap}
                    highlightSamples={{ [hoverEvent.source]: "#00a3a6" }}
                    labelMode="sample"
                    size={plateMap.format.rows > 8 ? 18 : 32}
                  />
                </div>
                <div>
                  <div
                    className="text-[10px] mb-1 uppercase tracking-[0.1em]"
                    style={{
                      color: "#ed6e6c",
                      fontWeight: 700,
                      fontFamily: '"Raleway", sans-serif',
                    }}
                  >
                    target — {hoverEvent.b.plate}
                  </div>
                  <PlateGrid
                    format={plateMap.format}
                    plateId={hoverEvent.b.plate}
                    plateMap={plateMap}
                    highlightSamples={{ [hoverEvent.target]: "#ed6e6c" }}
                    labelMode="sample"
                    size={plateMap.format.rows > 8 ? 18 : 32}
                  />
                </div>
              </div>
            ) : (
              <PlateGrid
                format={plateMap.format}
                plateId={activePlate}
                plateMap={plateMap}
                highlightSamples={highlightSamples}
                labelMode="sample"
                size={plateMap.format.rows > 8 ? 24 : 44}
                arrows={plateArrows}
              />
            )}

            <div
              className="mt-3 flex items-center gap-4 text-[11px] flex-wrap"
              style={{ color: "#797870" }}
            >
              <span className="flex items-center gap-1.5">
                <span
                  className="w-3 h-3 rounded-sm"
                  style={{ background: "#00a3a6" }}
                />
                source
              </span>
              <span className="flex items-center gap-1.5">
                <span
                  className="w-3 h-3 rounded-sm"
                  style={{ background: "#ed6e6c" }}
                />
                target
              </span>
              {showArrows && (
                <>
                  <span
                    aria-hidden="true"
                    style={{
                      width: 1,
                      height: 12,
                      background: "#c4c0b3",
                      margin: "0 4px",
                    }}
                  />
                  <span className="flex items-center gap-1.5">
                    <svg width="18" height="6" aria-hidden="true">
                      <line x1="1" y1="3" x2="17" y2="3" stroke="#ed6e6c" strokeWidth="2" />
                    </svg>
                    adjacent
                  </span>
                  <span className="flex items-center gap-1.5">
                    <svg width="18" height="6" aria-hidden="true">
                      <line x1="1" y1="3" x2="17" y2="3" stroke="#e3a100" strokeWidth="2" />
                    </svg>
                    Δ=2
                  </span>
                  <span className="flex items-center gap-1.5">
                    <svg width="18" height="6" aria-hidden="true">
                      <line x1="1" y1="3" x2="17" y2="3" stroke="#423089" strokeWidth="2" />
                    </svg>
                    cascade
                  </span>
                  <span className="flex items-center gap-1.5">
                    <svg width="18" height="6" aria-hidden="true">
                      <line x1="1" y1="3" x2="17" y2="3" stroke="#797870" strokeWidth="2" />
                    </svg>
                    further
                  </span>
                </>
              )}
            </div>
          </div>

          <div className="lg:w-[480px] lg:flex-shrink-0">
            <div className="flex items-center justify-between mb-3 flex-wrap gap-2">
              <div
                className="text-[10px] tracking-[0.15em] uppercase"
                style={{
                  color: "#ed6e6c",
                  fontWeight: 700,
                  fontFamily: '"Raleway", sans-serif',
                }}
              >
                Events ({filteredEvents.length})
              </div>
              <div className="flex items-center gap-2 flex-wrap">
                <label
                  className="flex items-center gap-1 text-[11px] cursor-pointer select-none"
                  style={{ color: "#275662", fontWeight: 600 }}
                >
                  <input
                    type="checkbox"
                    checked={showArrows}
                    onChange={(e) => setShowArrows(e.target.checked)}
                    style={{ accentColor: "#00a3a6" }}
                  />
                  show arrows
                </label>
                <select
                  value={eventFilter}
                  onChange={(e) => setEventFilter(e.target.value)}
                  className="px-2 py-1 text-[11px] rounded-sm"
                  style={{
                    border: "1px solid #c4c0b3",
                    background: "#fff",
                    color: "#275662",
                  }}
                >
                  <option value="all">involving {activePlate}</option>
                  <option value="thisPlate">within {activePlate}</option>
                  <option value="adjacent">adjacent wells only</option>
                  <option value="interPlate">
                    inter-plate ({interPlateCount})
                  </option>
                </select>
              </div>
            </div>
            <div
              className="rounded-sm overflow-auto max-h-[520px]"
              style={{ border: "1px solid #e6e8e8" }}
            >
              {filteredEvents.map((e) => {
                const samePlate = e.a.plate === e.b.plate;
                const d = samePlate
                  ? Math.max(
                      Math.abs(e.a.row - e.b.row),
                      Math.abs(e.a.col - e.b.col),
                    )
                  : null;
                return (
                  <button
                    key={e.id}
                    onClick={() => onPick && onPick(e.id)}
                    onMouseEnter={() => setHoverEvent(e)}
                    onMouseLeave={() => setHoverEvent(null)}
                    className="w-full text-left px-3 py-2.5 text-[12px]"
                    style={{
                      borderBottom: "1px solid #f0f2f2",
                      background: "#fff",
                    }}
                    onMouseOver={(ev) =>
                      (ev.currentTarget.style.background = "#f6f7f7")
                    }
                    onMouseOut={(ev) =>
                      (ev.currentTarget.style.background = "#fff")
                    }
                  >
                    <div className="flex items-center justify-between gap-2">
                      <span style={{ color: "#275662", fontWeight: 600 }}>
                        {samePlate ? (
                          <>
                            {e.a.plate} · {wellLabel(e.a.row, e.a.col)} →{" "}
                            {wellLabel(e.b.row, e.b.col)}
                          </>
                        ) : (
                          <>
                            {e.a.plate}:{wellLabel(e.a.row, e.a.col)} →{" "}
                            {e.b.plate}:{wellLabel(e.b.row, e.b.col)}
                          </>
                        )}
                      </span>
                      {!samePlate ? (
                        <Pill tone="primary">inter-plate</Pill>
                      ) : d === 1 ? (
                        <Pill tone="bad">adjacent</Pill>
                      ) : d === 2 ? (
                        <Pill tone="warn">close (Δ=2)</Pill>
                      ) : (
                        <Pill>Δ={d}</Pill>
                      )}
                    </div>
                    <div
                      className="text-[11px] mt-0.5"
                      style={{ color: "#797870" }}
                    >
                      {e.source} → {e.target} · probability {e.score.toFixed(2)}
                    </div>
                  </button>
                );
              })}
              {filteredEvents.length === 0 && (
                <div
                  className="px-3 py-6 text-center text-[12px]"
                  style={{ color: "#797870" }}
                >
                  No events match this filter.
                </div>
              )}
            </div>
            <p
              className="text-[11px] mt-2"
              style={{ color: "#797870" }}
            >
              Hover an event to highlight its wells. Click to open in Guided
              validation.
            </p>
          </div>
        </div>
      )}

      {/* ============================================================
          EDIT MODE
          ============================================================ */}
      {mode === "edit" && (
        <PlateEditor
          samples={samples}
          plateMap={plateMap}
          setPlateMap={setPlateMap}
        />
      )}

      {/* Empty-state messages */}
      {(mode === "overview" || mode === "inspect") && !plateMap && (
        <div
          className="p-6 rounded-sm text-[13px]"
          style={{
            background: "#f6f7f7",
            border: "1px solid #e6e8e8",
            color: "#275662",
          }}
        >
          No plate map loaded. Upload <code>plate_map.tsv</code> above, or
          switch to Edit mode to build one manually.
        </div>
      )}
    </div>
  );
};

/* ---------- VALIDATE TAB ---------- */
const ValidateTab = ({
  events,
  selected,
  onSelect,
  scatter,
  diag,
  above,
  missing,
  autoScore,
  hasAb,
  setVerdict,
  setNote,
  metadata,
  plateMap,
}) => {
  const sel = selected || events[0];
  if (!sel) return null;
  const idx = events.findIndex((e) => e.id === sel.id);
  const related = areRelated(metadata, sel.source, sel.target);
  const pd = plateDistance(plateMap, sel.source, sel.target);

  return (
    <div className="grid lg:grid-cols-[260px_1fr] gap-8">
      <aside>
        <div
          className="text-[10px] tracking-[0.15em] uppercase mb-3 flex items-center justify-between"
          style={{
            color: "#ed6e6c",
            fontWeight: 700,
            fontFamily: '"Raleway", sans-serif',
          }}
        >
          <span>Event queue</span>
          <span className="tabular" style={{ color: "#275662" }}>
            {idx + 1}/{events.length}
          </span>
        </div>
        <EventQueue events={events} currentId={sel.id} onSelect={onSelect} />
      </aside>

      <div>
        <SectionTitle
          eyebrow={`Event ${idx + 1} of ${events.length}`}
          title={`${sel.source} → ${sel.target}`}
        >
          The four criteria from the CroCoDeEL wiki. The assisted score is a hint,
          not a verdict — the plot is the final arbiter.
        </SectionTitle>

        <CascadeBanner
          cascade={sel.cascade}
          onJumpToUpstream={(id) => onSelect(id)}
        />

        <div className="grid md:grid-cols-[minmax(0,1fr)_minmax(0,1fr)] gap-6 mt-6">
          <div>
            {hasAb ? (
              <Scatterplot scatter={scatter} width={520} height={450} />
            ) : (
              <div
                className="p-4 text-[13px] rounded-sm"
                style={{ background: "#fdeceb", border: "1px solid #ed6e6c", color: "#8a2422" }}
              >
                Upload <code>species_abundance.tsv</code> to see the plot and
                enable assisted diagnostics.
              </div>
            )}
            <div className="mt-4 grid grid-cols-2 gap-2">
              <Diag
                label="Probability"
                value={sel.score.toFixed(3)}
                tone={sel.score > 0.9 ? "good" : sel.score > 0.7 ? "warn" : "bad"}
              />
              <Diag label="Rate" value={`${(sel.rate * 100).toFixed(2)}%`} />
            </div>

            {plateMap && pd?.samePlate && (
              <div className="mt-4">
                <div
                  className="text-[10px] tracking-[0.15em] uppercase mb-2"
                  style={{
                    color: "#ed6e6c",
                    fontWeight: 700,
                    fontFamily: '"Raleway", sans-serif',
                  }}
                >
                  Position on {plateMap.bySample[sel.source]?.plate}
                </div>
                <PlateGrid
                  format={plateMap.format}
                  plateId={plateMap.bySample[sel.source]?.plate}
                  plateMap={plateMap}
                  highlightSamples={{
                    [sel.source]: "#00a3a6",
                    [sel.target]: "#ed6e6c",
                  }}
                  labelMode="none"
                  size={18}
                />
              </div>
            )}

            {metadata &&
              (metadata.bySample[sel.source] || metadata.bySample[sel.target]) && (
                <div
                  className="mt-4 p-3 rounded-sm text-[12px]"
                  style={{ background: "#f6f7f7", border: "1px solid #e6e8e8" }}
                >
                  <div
                    className="text-[10px] tracking-[0.15em] uppercase mb-3"
                    style={{
                      color: "#ed6e6c",
                      fontWeight: 700,
                      fontFamily: '"Raleway", sans-serif',
                    }}
                  >
                    Sample context
                  </div>
                  <div className="space-y-3">
                    <div>
                      <div className="flex items-center gap-2 mb-1">
                        <span
                          className="w-2 h-2 rounded-full"
                          style={{ background: "#00a3a6" }}
                        />
                        <span style={{ color: "#797870", fontSize: 11 }}>
                          source
                        </span>
                        <span
                          style={{
                            color: "#275662",
                            fontWeight: 600,
                            fontFamily: '"Raleway", sans-serif',
                          }}
                        >
                          {sel.source}
                        </span>
                      </div>
                      <SampleFlags flags={flagSample(sel.source, metadata)} />
                    </div>
                    <div>
                      <div className="flex items-center gap-2 mb-1">
                        <span
                          className="w-2 h-2 rounded-full"
                          style={{ background: "#ed6e6c" }}
                        />
                        <span style={{ color: "#797870", fontSize: 11 }}>
                          target
                        </span>
                        <span
                          style={{
                            color: "#275662",
                            fontWeight: 600,
                            fontFamily: '"Raleway", sans-serif',
                          }}
                        >
                          {sel.target}
                        </span>
                      </div>
                      <SampleFlags flags={flagSample(sel.target, metadata)} />
                    </div>
                  </div>
                </div>
              )}
          </div>

          <div>
            <div
              className="p-4 mb-4 rounded-sm"
              style={{ background: "#f6f7f7", border: "1px solid #e6e8e8" }}
            >
              <div className="flex items-center justify-between mb-3">
                <div
                  className="text-[10px] tracking-[0.15em] uppercase"
                  style={{
                    color: "#ed6e6c",
                    fontWeight: 700,
                    fontFamily: '"Raleway", sans-serif',
                  }}
                >
                  Assisted score
                </div>
                <div
                  className="tabular"
                  style={{ color: "#275662", fontFamily: '"Raleway", sans-serif' }}
                >
                  <span style={{ fontSize: 32, fontWeight: 800 }}>{autoScore.good}</span>
                  <span style={{ fontSize: 16, color: "#797870" }}>
                    /{autoScore.total}
                  </span>
                </div>
              </div>
              <div className="space-y-1.5">
                {autoScore.reasons.length === 0 && (
                  <div className="text-[12px]" style={{ color: "#797870" }}>
                    Upload the abundance table to compute.
                  </div>
                )}
                {autoScore.reasons.map((r, i) => (
                  <div key={i} className="flex items-start gap-2 text-[12px]">
                    {r.ok ? (
                      <CheckCircle2
                        className="w-3.5 h-3.5 shrink-0 mt-0.5"
                        style={{ color: "#00a3a6" }}
                      />
                    ) : (
                      <XCircle
                        className="w-3.5 h-3.5 shrink-0 mt-0.5"
                        style={{ color: "#ed6e6c" }}
                      />
                    )}
                    <span style={{ color: "#275662" }}>{r.label}</span>
                  </div>
                ))}
              </div>
            </div>

            <Criterion
              n="01"
              title="Shape of the contamination line"
              wiki="Must be an actual straight line, not a scatter of points."
              pass={diag?.r2 != null ? diag.r2 > 0.8 : null}
              value={
                diag?.r2 != null
                  ? `R² = ${diag.r2.toFixed(3)}`
                  : "abundance table required"
              }
            />
            <Criterion
              n="02"
              title="Number of points on the line"
              wiki="Fewer than ~10 species → possibly random."
              pass={diag?.n != null ? diag.n >= 10 : null}
              value={
                diag?.n != null ? `${diag.n} species` : "abundance table required"
              }
            />
            <Criterion
              n="03"
              title="Abundant source species present in target"
              wiki="All abundant species in the source should appear in the target."
              pass={missing != null ? missing <= 2 : null}
              value={
                missing != null ? `${missing} missing` : "abundance table required"
              }
            />
            <Criterion
              n="04"
              title="Points above the contamination line"
              wiki="Near zero expected. A few tolerable if the source is itself contaminated (cascade)."
              pass={above != null ? above <= 3 : null}
              value={
                above != null ? `${above} above` : "abundance table required"
              }
            />

            {metadata && (
              <ContextualCriterion
                n="05"
                title="Related samples"
                hint="Longitudinal, same subject or same related group → false positive risk"
                verdict={
                  related?.related === true
                    ? {
                        tone: "bad",
                        text:
                          related.kind === "group"
                            ? `same group (${related.value})`
                            : `same subject (${related.value})`,
                      }
                    : related?.related === false
                      ? { tone: "good", text: "different subjects" }
                      : { tone: "neutral", text: "sample not referenced" }
                }
              />
            )}

            {plateMap && (
              <ContextualCriterion
                n="06"
                title="Proximity on plate"
                hint="Well-to-well leakage → immediate neighbors = strong suspicion"
                verdict={
                  pd == null
                    ? { tone: "neutral", text: "position unknown" }
                    : !pd.samePlate
                      ? {
                          tone: "warn",
                          text: "different plates — well-to-well unlikely",
                        }
                      : pd.distance <= 1
                        ? { tone: "bad", text: "adjacent wells" }
                        : pd.distance === 2
                          ? { tone: "warn", text: "Δ=2 (close)" }
                          : {
                              tone: "good",
                              text: `Δ=${pd.distance} (distant)`,
                            }
                }
              />
            )}

            {sel.introduced.length > 0 && (
              <div className="mt-4">
                <div
                  className="text-[10px] tracking-[0.15em] uppercase mb-2"
                  style={{
                    color: "#ed6e6c",
                    fontWeight: 700,
                    fontFamily: '"Raleway", sans-serif',
                  }}
                >
                  Introduced species ({sel.introduced.length})
                </div>
                <div
                  className="flex flex-wrap gap-1 max-h-28 overflow-auto p-2 rounded-sm"
                  style={{ background: "#fff", border: "1px solid #e6e8e8" }}
                >
                  {sel.introduced.slice(0, 80).map((s, i) => (
                    <span
                      key={i}
                      className="text-[11px] px-1.5 py-0.5 rounded-sm"
                      style={{
                        background: "#f6f7f7",
                        color: "#275662",
                        fontFamily: "system-ui, monospace",
                      }}
                    >
                      {s}
                    </span>
                  ))}
                  {sel.introduced.length > 80 && (
                    <span
                      className="text-[11px] px-1.5 py-0.5"
                      style={{ color: "#797870" }}
                    >
                      + {sel.introduced.length - 80} more
                    </span>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>

        <div className="mt-8 pt-6" style={{ borderTop: "1px solid #e6e8e8" }}>
          <div
            className="text-[10px] tracking-[0.15em] uppercase mb-3"
            style={{
              color: "#ed6e6c",
              fontWeight: 700,
              fontFamily: '"Raleway", sans-serif',
            }}
          >
            Your verdict
          </div>
          <div className="flex flex-wrap gap-2 mb-4">
            <VerdictBtn
              active={sel.verdict === "true_positive"}
              onClick={() => setVerdict(sel.id, "true_positive")}
              tone="good"
              icon={CheckCircle2}
            >
              True positive
            </VerdictBtn>
            <VerdictBtn
              active={sel.verdict === "false_positive"}
              onClick={() => setVerdict(sel.id, "false_positive")}
              tone="bad"
              icon={XCircle}
            >
              False positive
            </VerdictBtn>
            <VerdictBtn
              active={sel.verdict === "uncertain"}
              onClick={() => setVerdict(sel.id, "uncertain")}
              tone="warn"
              icon={HelpCircle}
            >
              Uncertain
            </VerdictBtn>
            <VerdictBtn
              active={sel.verdict === "pending"}
              onClick={() => setVerdict(sel.id, "pending")}
              tone="neutral"
              icon={X}
            >
              Reset
            </VerdictBtn>
          </div>
          <textarea
            value={sel.notes}
            onChange={(e) => setNote(sel.id, e.target.value)}
            placeholder="Notes: related samples? plate position? cascade?"
            rows={3}
            className="w-full px-3 py-2 text-[13px] rounded-sm outline-none"
            style={{ border: "1px solid #c4c0b3" }}
          />
          <div className="mt-4 flex justify-between">
            <button
              onClick={() => onSelect(events[Math.max(0, idx - 1)].id)}
              disabled={idx === 0}
              className="px-5 py-2 text-[12px] rounded-sm"
              style={{
                border: "1px solid #275662",
                background: "#fff",
                color: "#275662",
                fontWeight: 700,
                opacity: idx === 0 ? 0.3 : 1,
                cursor: idx === 0 ? "not-allowed" : "pointer",
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              ← Previous
            </button>
            <button
              onClick={() =>
                onSelect(events[Math.min(events.length - 1, idx + 1)].id)
              }
              disabled={idx === events.length - 1}
              className="px-5 py-2 text-[12px] rounded-sm"
              style={{
                background: "#00a3a6",
                color: "white",
                fontWeight: 700,
                opacity: idx === events.length - 1 ? 0.3 : 1,
                cursor: idx === events.length - 1 ? "not-allowed" : "pointer",
                border: "none",
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              Next event →
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

