/* ============================================================================
   8. MAIN APP
   ============================================================================ */

export default function App() {
  const [rawEvents, setRawEvents] = useState([]);
  const [runMetadata, setRunMetadata] = useState(null);
  const [ab, setAb] = useState(null);
  const [metadata, setMetadata] = useState(null);
  const [plateMap, setPlateMap] = useState(null);
  const [tab, setTab] = useState("overview");
  const [selId, setSelId] = useState(null);
  const [filter, setFilter] = useState({
    q: "",
    minScore: 0,
    verdict: "all",
    minRate: 0,
    hideRelated: false,
    adjacentOnly: false,
  });
  const [sort, setSort] = useState({ by: "score", dir: "desc" });
  const [err, setErr] = useState(null);
  const eventFileRef = useRef(null);
  const abFileRef = useRef(null);

  /* When a CroCoDeEL run header carries explicit cutoffs, pre-set the
     events-table filters to those values. The user can still lower them
     manually if they want to inspect events the cutoff filtered out
     (though CroCoDeEL itself wouldn't have written them anyway). */
  useEffect(() => {
    const probCutoff = parseFloat(runMetadata?.probability_cutoff);
    const rateCutoff = parseFloat(runMetadata?.rate_cutoff);
    setFilter((f) => ({
      ...f,
      minScore:
        Number.isFinite(probCutoff) && probCutoff > 0 ? probCutoff : f.minScore,
      minRate:
        Number.isFinite(rateCutoff) && rateCutoff > 0 ? rateCutoff : f.minRate,
    }));
  }, [runMetadata]);

  /* ---- derived state ---- */
  const events = useMemo(
    () => detectCascades(rawEvents, ab),
    [rawEvents, ab],
  );

  const allSamples = useMemo(() => {
    if (ab) return ab.samples;
    const s = new Set();
    rawEvents.forEach((e) => {
      s.add(e.source);
      s.add(e.target);
    });
    return Array.from(s).sort();
  }, [ab, rawEvents]);

  /** Sanity check — warn when event sample names don't match abundance columns */
  const sampleMismatches = useMemo(() => {
    if (!ab || rawEvents.length === 0) return null;
    const abSet = new Set(ab.samples);
    const abSetLC = new Set(ab.samples.map((s) => s.toLowerCase().trim()));
    const missing = new Set();
    const casediff = new Set();
    rawEvents.forEach((e) => {
      [e.source, e.target].forEach((name) => {
        if (!name) return;
        if (abSet.has(name)) return;
        if (abSetLC.has(String(name).toLowerCase().trim())) {
          casediff.add(name);
        } else {
          missing.add(name);
        }
      });
    });
    if (missing.size === 0 && casediff.size === 0) return null;
    return {
      missing: Array.from(missing).slice(0, 10),
      missingCount: missing.size,
      casediff: Array.from(casediff).slice(0, 5),
      casediffCount: casediff.size,
    };
  }, [ab, rawEvents]);

  const filtered = useMemo(() => {
    const q = filter.q.trim().toLowerCase();
    let res = events.filter((e) => {
      if (e.score < filter.minScore) return false;
      if (e.rate < filter.minRate) return false;
      if (filter.verdict !== "all" && e.verdict !== filter.verdict) return false;
      if (filter.hideRelated && areRelated(metadata, e.source, e.target)?.related === true)
        return false;
      if (filter.adjacentOnly) {
        const pd = plateDistance(plateMap, e.source, e.target);
        if (!pd || !pd.samePlate || pd.distance == null || pd.distance > 1)
          return false;
      }
      if (q) {
        const hay = `${e.source} ${e.target} ${e.introduced.join(
          " ",
        )}`.toLowerCase();
        if (!hay.includes(q)) return false;
      }
      return true;
    });
    res.sort((a, b) => {
      const av = a[sort.by];
      const bv = b[sort.by];
      if (typeof av === "string") {
        return sort.dir === "asc"
          ? av.localeCompare(bv)
          : bv.localeCompare(av);
      }
      return sort.dir === "asc" ? av - bv : bv - av;
    });
    return res;
  }, [events, filter, sort, metadata, plateMap]);

  const counts = useMemo(() => {
    const c = {
      total: events.length,
      tp: 0,
      fp: 0,
      uncertain: 0,
      pending: 0,
      samples: new Set(),
      avgRate: 0,
    };
    let rateSum = 0;
    events.forEach((e) => {
      c[
        e.verdict === "true_positive"
          ? "tp"
          : e.verdict === "false_positive"
            ? "fp"
            : e.verdict === "uncertain"
              ? "uncertain"
              : "pending"
      ]++;
      c.samples.add(e.source);
      c.samples.add(e.target);
      rateSum += e.rate;
    });
    c.avgRate = events.length ? rateSum / events.length : 0;
    c.samples = c.samples.size;
    return c;
  }, [events]);

  const selected =
    events.find((e) => e.id === selId) || events[0] || null;
  const setVerdict = (id, verdict) =>
    setRawEvents((prev) =>
      prev.map((e) => (e.id === id ? { ...e, verdict } : e)),
    );
  const setNote = (id, notes) =>
    setRawEvents((prev) =>
      prev.map((e) => (e.id === id ? { ...e, notes } : e)),
    );

  /* ---- file loaders ---- */
  const loadEvents = async (file) => {
    try {
      const text = await file.text();
      const parsed = parseEvents(text);
      setRawEvents(parsed.events);
      setRunMetadata(parsed.runMetadata);
      setErr(null);
      setTab("overview");
    } catch (e) {
      setErr(`Events file: ${e.message}`);
    }
  };

  const loadAbundance = async (file) => {
    try {
      const text = await file.text();
      const parsed = parseAbundance(text);
      if (!parsed) throw new Error("Could not parse abundance table");
      setAb(parsed);
      setErr(null);
    } catch (e) {
      setErr(`Abundance file: ${e.message}`);
    }
  };

  const [demoLoading, setDemoLoading] = useState(false);
  const loadDemo = async () => {
    setDemoLoading(true);
    setErr(null);
    try {
      // Derive the base URL from the current location instead of
      // import.meta.env.BASE_URL — that keeps this file parseable in
      // non-module contexts (e.g. Claude's artifact preview) while still
      // working correctly when Vite serves it under a nested base path.
      const path = window.location.pathname;
      const base = path.endsWith("/")
        ? path
        : path.replace(/\/[^/]*$/, "/") || "/";
      const join = (p) => `${base.replace(/\/$/, "")}/demo/${p}`;

      // Required files
      const [evRes, abRes] = await Promise.all([
        fetch(join("contamination_events.tsv")),
        fetch(join("species_abundance.tsv")),
      ]);
      if (!evRes.ok) throw new Error(`events (${evRes.status})`);
      if (!abRes.ok) throw new Error(`abundance (${abRes.status})`);
      const [evText, abText] = await Promise.all([evRes.text(), abRes.text()]);
      const parsedAb = parseAbundance(abText);
      if (!parsedAb) throw new Error("Could not parse demo abundance table");
      const parsedEvents = parseEvents(evText);
      setRawEvents(parsedEvents.events);
      setRunMetadata(parsedEvents.runMetadata);
      setAb(parsedAb);

      // Optional files — load if present, ignore 404s silently
      try {
        const pmRes = await fetch(join("plate_map.tsv"));
        if (pmRes.ok) {
          const pmText = await pmRes.text();
          setPlateMap(parsePlateMap(pmText));
        }
      } catch {
        // ignore
      }
      try {
        const mdRes = await fetch(join("metadata.tsv"));
        if (mdRes.ok) {
          const mdText = await mdRes.text();
          setMetadata(parseMetadata(mdText));
        }
      } catch {
        // ignore
      }

      setTab("overview");
    } catch (e) {
      setErr(
        `Demo data: ${e.message}. Make sure public/demo/contamination_events.tsv and public/demo/species_abundance.tsv exist in the deployed site.`,
      );
    } finally {
      setDemoLoading(false);
    }
  };

  /* ---- export ---- */
  const downloadFile = (content, name, mime) => {
    const blob = new Blob([content], { type: mime });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = name;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportReport = (onlyTP = true) => {
    const kept = events.filter((e) =>
      onlyTP
        ? e.verdict === "true_positive"
        : e.verdict !== "false_positive",
    );
    const header = [
      "source",
      "target",
      "contamination_rate",
      "probability",
      "introduced_species",
      "verdict",
      "notes",
    ];
    const lines = [header.join("\t")];
    kept.forEach((e) => {
      lines.push(
        [
          e.source,
          e.target,
          e.rate,
          e.score,
          e.introduced.join(","),
          e.verdict,
          e.notes.replace(/\t/g, " "),
        ].join("\t"),
      );
    });
    downloadFile(
      lines.join("\n"),
      `contamination_events_curated${onlyTP ? "_TP_only" : ""}.tsv`,
      "text/tab-separated-values",
    );
  };

  const exportJSON = () => {
    const payload = {
      generated: new Date().toISOString(),
      counts: {
        total: counts.total,
        true_positive: counts.tp,
        false_positive: counts.fp,
        uncertain: counts.uncertain,
        pending: counts.pending,
      },
      has_metadata: !!metadata,
      has_plate_map: !!plateMap,
      events: events.map((e) => ({
        source: e.source,
        target: e.target,
        contamination_rate: e.rate,
        probability: e.score,
        introduced_species: e.introduced,
        verdict: e.verdict,
        notes: e.notes,
        relatedness: areRelated(metadata, e.source, e.target),
        plate_distance: plateDistance(plateMap, e.source, e.target),
        cascade: e.cascade,
      })),
    };
    downloadFile(
      JSON.stringify(payload, null, 2),
      "crocodeel_curation_report.json",
      "application/json",
    );
  };

  /* ---- diagnostics for selected event ---- */
  const scatter = useMemo(
    () => (selected ? buildScatter(ab, selected) : null),
    [ab, selected],
  );
  const diag = useMemo(() => lineDiagnostics(scatter), [scatter]);
  const above = useMemo(() => pointsAboveLine(scatter), [scatter]);
  const missing = useMemo(
    () =>
      selected && ab
        ? missingAbundantFromSource(ab, selected.source, selected.target)
        : null,
    [ab, selected],
  );
  const autoScore = useMemo(
    () => automaticScore(diag, above, missing),
    [diag, above, missing],
  );

  /* ============================================================
     RENDER
     ============================================================ */
  return (
    <div
      className="min-h-screen"
      style={{
        background: "#fff",
        color: "#275662",
        fontFamily:
          '"Avenir Next", "Nunito Sans", system-ui, -apple-system, sans-serif',
      }}
    >
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Raleway:wght@400;500;600;700;800&family=Nunito+Sans:opsz,wght@6..12,400;6..12,500;6..12,600;6..12,700&display=swap');
        .tabular { font-variant-numeric: tabular-nums; }
        ::-webkit-scrollbar { width: 8px; height: 8px; }
        ::-webkit-scrollbar-thumb { background: #c4c0b3; border-radius: 4px; }
        ::-webkit-scrollbar-thumb:hover { background: #00a3a6; }
      `}</style>

      {/* ==================== HEADER ==================== */}
      <header style={{ borderBottom: "3px solid #00a3a6", background: "#fff" }}>
        <div className="max-w-7xl mx-auto px-6 py-5">
          <div className="flex items-center gap-8 flex-wrap">
            <RepubliqueFrancaise height={46} />
            <div style={{ width: 1, height: 46, background: "#c4c0b3" }} />
            <InraeLogo height={36} />
            <div style={{ width: 1, height: 46, background: "#c4c0b3" }} />
            <div className="flex items-center gap-3">
              <img
                src={CROCODEEL_LOGO}
                alt="CroCoDeEL"
                style={{
                  height: 46,
                  width: 46,
                  borderRadius: "50%",
                  display: "block",
                }}
              />
              <div className="leading-tight">
                <div
                  className="text-[20px]"
                  style={{
                    color: "#275662",
                    fontWeight: 800,
                    letterSpacing: "-0.01em",
                    fontFamily: '"Raleway", sans-serif',
                  }}
                >
                  CroCoDeEL
                </div>
                <div
                  className="text-[10px] uppercase tracking-[0.15em]"
                  style={{
                    color: "#797870",
                    fontFamily: '"Raleway", sans-serif',
                  }}
                >
                  Interpretation console
                </div>
              </div>
            </div>
          </div>
        </div>
      </header>

      {/* ==================== SUB-BANNER ==================== */}
      <section className="bg-white">
        <div className="max-w-7xl mx-auto px-6 py-8 grid md:grid-cols-[1fr_auto] gap-6 items-end">
          <div>
            <div className="flex items-center gap-2 mb-2">
              <Chevron size={14} color="#ed6e6c" />
              <span
                className="text-[11px] tracking-[0.15em] uppercase"
                style={{
                  color: "#ed6e6c",
                  fontWeight: 700,
                  fontFamily: '"Raleway", sans-serif',
                }}
              >
                Metagenomics · Cross-sample contamination detection
              </span>
            </div>
            <h1
              className="text-[42px] leading-[1.05] tracking-tight"
              style={{
                color: "#275662",
                fontWeight: 800,
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              Interpreting CroCoDeEL results
            </h1>
            <p className="mt-3 text-[15px] leading-relaxed text-stone-700 max-w-2xl">
              Upload your events file and abundance table, then walk through each
              flagged pair with interactive scatterplots, assisted diagnostics
              and a guided validation workflow. Export a curated TSV when you are
              done.
            </p>
            {/* Privacy badge — prominent, reassuring */}
            <div
              className="mt-4 inline-flex items-center gap-2 px-3 py-1.5 rounded-sm"
              style={{
                background: "rgba(0, 163, 166, 0.08)",
                border: "1px solid #00a3a6",
              }}
            >
              <ShieldCheck className="w-4 h-4" style={{ color: "#00a3a6" }} />
              <span
                className="text-[12px]"
                style={{
                  color: "#275662",
                  fontWeight: 600,
                  fontFamily: '"Raleway", sans-serif',
                }}
              >
                100% browser-based — your files never leave your computer
              </span>
            </div>
          </div>
          <div className="text-right">
            <a
              href="https://github.com/metagenopolis/CroCoDeEL"
              target="_blank"
              rel="noreferrer"
              className="inline-flex items-center gap-2 text-[12px] font-semibold hover:underline"
              style={{ color: "#00a3a6", fontFamily: '"Raleway", sans-serif' }}
            >
              github.com/metagenopolis/CroCoDeEL{" "}
              <ArrowRight className="w-3.5 h-3.5" />
            </a>
          </div>
        </div>
      </section>

      {/* ==================== UPLOAD BAR ==================== */}
      <section
        style={{
          background: "#f6f7f7",
          borderTop: "1px solid #e6e8e8",
          borderBottom: "1px solid #e6e8e8",
        }}
      >
        <div className="max-w-7xl mx-auto px-6 py-5">
          <div className="flex items-center justify-between gap-4 mb-3 flex-wrap">
            <div
              className="flex items-center gap-2 text-[11px]"
              style={{ color: "#797870", fontFamily: '"Raleway", sans-serif' }}
            >
              <ShieldCheck className="w-3.5 h-3.5" style={{ color: "#00a3a6" }} />
              <span>
                Files stay local: parsing happens entirely in your browser. No
                data is sent to any server.
              </span>
            </div>
            {(rawEvents.length > 0 || ab || metadata || plateMap) && (
              <button
                onClick={() => {
                  if (
                    window.confirm(
                      "Clear the entire session?\n\nThis removes the loaded events, abundance, metadata and plate map, plus all your verdicts and notes. The original files on disk are not affected.",
                    )
                  ) {
                    setRawEvents([]);
                    setRunMetadata(null);
                    setAb(null);
                    setMetadata(null);
                    setPlateMap(null);
                    setSelId(null);
                    setErr(null);
                    setTab("overview");
                  }
                }}
                className="px-3 py-1.5 text-[11px] rounded-sm flex items-center gap-1.5"
                style={{
                  background: "#fff",
                  color: "#797870",
                  border: "1px solid #e6e8e8",
                  fontWeight: 600,
                  fontFamily: '"Raleway", sans-serif',
                }}
                onMouseOver={(e) => {
                  e.currentTarget.style.borderColor = "#ed6e6c";
                  e.currentTarget.style.color = "#ed6e6c";
                }}
                onMouseOut={(e) => {
                  e.currentTarget.style.borderColor = "#e6e8e8";
                  e.currentTarget.style.color = "#797870";
                }}
              >
                <X className="w-3 h-3" />
                Clear all session
              </button>
            )}
          </div>
          <div className="grid md:grid-cols-2 gap-4">
            <UploadCard
              label="contamination_events.tsv"
              hint="CroCoDeEL output — required"
              filename={events.length ? `${events.length} events loaded` : null}
              onFile={loadEvents}
              primary
              inputRef={eventFileRef}
              info={
                <>
                  <div style={{ fontWeight: 700, marginBottom: 4 }}>
                    CroCoDeEL output file (TSV)
                  </div>
                  Required columns:{" "}
                  <code style={{ fontFamily: "ui-monospace, monospace" }}>
                    source
                  </code>
                  ,{" "}
                  <code style={{ fontFamily: "ui-monospace, monospace" }}>
                    target
                  </code>
                  ,{" "}
                  <code style={{ fontFamily: "ui-monospace, monospace" }}>
                    rate
                  </code>
                  ,{" "}
                  <code style={{ fontFamily: "ui-monospace, monospace" }}>
                    probability
                  </code>
                  ,{" "}
                  <code style={{ fontFamily: "ui-monospace, monospace" }}>
                    contamination_specific_species
                  </code>
                  . An optional first comment line starting with{" "}
                  <code style={{ fontFamily: "ui-monospace, monospace" }}>#</code>{" "}
                  carries CroCoDeEL run parameters and is shown in the
                  Overview tab.
                </>
              }
              onDownload={
                rawEvents.length
                  ? () =>
                      downloadText(
                        eventsToTSV(rawEvents, runMetadata),
                        "contamination_events.tsv",
                      )
                  : undefined
              }
              onClear={
                rawEvents.length
                  ? () => {
                      setRawEvents([]);
                      setRunMetadata(null);
                      setSelId(null);
                    }
                  : undefined
              }
            />
            <UploadCard
              label="species_abundance.tsv"
              hint="Abundance table — enables scatterplots and assisted scoring"
              filename={
                ab
                  ? `${ab.samples.length} samples × ${ab.species.length} species`
                  : null
              }
              onFile={loadAbundance}
              inputRef={abFileRef}
              info={
                <>
                  <div style={{ fontWeight: 700, marginBottom: 4 }}>
                    Species × sample abundance matrix (TSV)
                  </div>
                  First column lists species names, every other column is a
                  sample. Values are normalized to relative abundances
                  (summing to 1 per sample) at parse time. Loading this file
                  unlocks scatterplots, assisted scoring criteria, and
                  inline mini-scatterplots in Guided validation.
                </>
              }
              onDownload={
                ab
                  ? () =>
                      downloadText(abundanceToTSV(ab), "species_abundance.tsv")
                  : undefined
              }
              onClear={ab ? () => setAb(null) : undefined}
            />
            <MetadataUploadCard
              metadata={metadata}
              setMetadata={setMetadata}
              setErr={setErr}
            />
            <PlateUploadCard
              plateMap={plateMap}
              setPlateMap={setPlateMap}
              setErr={setErr}
            />
          </div>
        </div>
        {err && (
          <div className="max-w-7xl mx-auto px-6 pb-4">
            <div
              className="flex items-center gap-2 text-sm px-3 py-2 rounded-sm"
              style={{
                background: "#fdeceb",
                border: "1px solid #ed6e6c",
                color: "#8a2422",
              }}
            >
              <AlertCircle className="w-4 h-4" />
              {err}
            </div>
          </div>
        )}
        {sampleMismatches && (
          <div className="max-w-7xl mx-auto px-6 pb-4">
            <div
              className="flex items-start gap-2 text-[13px] px-3 py-2 rounded-sm"
              style={{
                background: "#fff3cd",
                border: "1px solid #e3a100",
                color: "#6b4500",
              }}
            >
              <AlertCircle className="w-4 h-4 shrink-0 mt-0.5" />
              <div>
                <strong>Sample names in events don't all match the abundance table.</strong>{" "}
                {sampleMismatches.missingCount > 0 && (
                  <>
                    {sampleMismatches.missingCount} sample
                    {sampleMismatches.missingCount > 1 ? "s are" : " is"}{" "}
                    missing — scatterplots will show an error for those events.
                    First few:{" "}
                    <code style={{ fontFamily: "system-ui, monospace" }}>
                      {sampleMismatches.missing.join(", ")}
                      {sampleMismatches.missingCount > 10 ? " …" : ""}
                    </code>
                    .{" "}
                  </>
                )}
                {sampleMismatches.casediffCount > 0 && (
                  <>
                    {sampleMismatches.casediffCount} other
                    {sampleMismatches.casediffCount > 1 ? "s" : ""} differ only
                    by case/whitespace and are auto-matched.
                  </>
                )}
              </div>
            </div>
          </div>
        )}
      </section>

      {/* ==================== CONTENT ==================== */}
      <div className="max-w-7xl mx-auto px-6 py-8">
        <nav
          className="flex flex-wrap gap-0 mb-8"
          style={{ borderBottom: "2px solid #e6e8e8" }}
        >
            {[
              { id: "overview", label: "Overview", icon: BookOpen, requiresData: false },
              { id: "table", label: "Events table", icon: TableIcon, requiresData: true },
              { id: "scatter", label: "Scatterplots", icon: ScatterIcon, requiresData: true },
              { id: "network", label: "Network", icon: GitBranch, requiresData: true },
              { id: "plate", label: "Plate map", icon: MapPin, requiresData: true },
              { id: "validate", label: "Guided validation", icon: ClipboardCheck, requiresData: true },
              { id: "export", label: "Export", icon: Download, requiresData: true },
              { id: "help", label: "Help", icon: HelpCircle, requiresData: false },
            ].map((t) => {
              const Icon = t.icon;
              const active = tab === t.id;
              const disabled = t.requiresData && events.length === 0;
              return (
                <button
                  key={t.id}
                  onClick={() => !disabled && setTab(t.id)}
                  disabled={disabled}
                  title={
                    disabled
                      ? "Load contamination_events.tsv first"
                      : undefined
                  }
                  className="px-5 py-3 text-[13px] flex items-center gap-2"
                  style={{
                    borderBottom: active
                      ? "3px solid #00a3a6"
                      : "3px solid transparent",
                    color: disabled
                      ? "#c4c0b3"
                      : active
                        ? "#275662"
                        : "#797870",
                    fontWeight: active ? 700 : 500,
                    marginBottom: "-2px",
                    fontFamily: '"Raleway", sans-serif',
                    cursor: disabled ? "not-allowed" : "pointer",
                    opacity: disabled ? 0.5 : 1,
                  }}
                >
                  <Icon className="w-4 h-4" />
                  {t.label}
                </button>
              );
            })}
          </nav>

          {(events.length > 0 || tab === "help" || tab === "overview") && (
            <>
          {tab === "overview" && (
            <Overview
              counts={counts}
              events={events}
              hasAb={!!ab}
              metadata={metadata}
              plateMap={plateMap}
              runMetadata={runMetadata}
              onOpen={(id) => {
                setSelId(id);
                setTab("validate");
              }}
              onLoadDemo={loadDemo}
              demoLoading={demoLoading}
            />
          )}
          {tab === "table" && (
            <EventsTable
              events={filtered}
              total={events.length}
              filter={filter}
              setFilter={setFilter}
              sort={sort}
              setSort={setSort}
              metadata={metadata}
              plateMap={plateMap}
              runMetadata={runMetadata}
              onPick={(id) => {
                setSelId(id);
                setTab(ab ? "validate" : "scatter");
              }}
              setVerdict={setVerdict}
            />
          )}
          {tab === "scatter" && (
            <ScatterTab
              events={events}
              ab={ab}
              metadata={metadata}
              plateMap={plateMap}
              onPick={(id) => {
                setSelId(id);
                setTab("validate");
              }}
            />
          )}
          {tab === "network" && (
            <NetworkTab
              events={events}
              onPick={(id) => {
                setSelId(id);
                setTab("validate");
              }}
            />
          )}
          {tab === "plate" && (
            <PlateTab
              events={events}
              plateMap={plateMap}
              setPlateMap={setPlateMap}
              samples={allSamples}
              onPick={(id) => {
                setSelId(id);
                setTab("validate");
              }}
            />
          )}
          {tab === "validate" && (
            <ValidateTab
              events={events}
              selected={selected}
              onSelect={setSelId}
              scatter={scatter}
              diag={diag}
              above={above}
              missing={missing}
              autoScore={autoScore}
              hasAb={!!ab}
              setVerdict={setVerdict}
              setNote={setNote}
              metadata={metadata}
              plateMap={plateMap}
            />
          )}
          {tab === "export" && (
            <ExportTab
              counts={counts}
              onExportTSV={exportReport}
              onExportJSON={exportJSON}
            />
          )}
          {tab === "help" && <HelpTab />}
            </>
          )}
        </div>

      {/* ==================== FOOTER ==================== */}
      <footer
        style={{
          background: "#fff",
          borderTop: "1px solid #e6e8e8",
          marginTop: 48,
        }}
      >
        <div className="max-w-7xl mx-auto px-6 py-8">
          <div className="flex flex-col items-center text-center gap-4">
            <Chevron size={18} color="#00a3a6" />
            <div
              className="text-[13px] whitespace-nowrap"
              style={{
                color: "#275662",
                fontWeight: 600,
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              Institut National de Recherche pour l'Agriculture, l'Alimentation et l'Environnement (INRAE)
            </div>
            <div className="flex items-center gap-6 mt-2">
              <RepubliqueFrancaise height={40} />
              <InraeLogo height={28} />
            </div>
            <div
              className="text-[11px] mt-4 max-w-2xl leading-relaxed"
              style={{ color: "#797870" }}
            >
              Interpretation aid for CroCoDeEL results. Cite: Goulet L. et al.,
              bioRxiv 2025,{" "}
              <a
                href="https://doi.org/10.1101/2025.01.15.633153"
                target="_blank"
                rel="noopener noreferrer"
                style={{
                  color: "#00a3a6",
                  textDecoration: "underline",
                }}
              >
                doi.org/10.1101/2025.01.15.633153
              </a>
              .
            </div>
            <div
              className="text-[11px] mt-1 italic"
              style={{ color: "#797870" }}
            >
              Created using Claude Opus 4.7, prompted by G. Gautreau.
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
}
